const fs = require('fs');
const path = require('path');

const targetDir = path.join(__dirname, 'src', 'app', 'crown-admin');

function walk(dir) {
    let results = [];
    const list = fs.readdirSync(dir);
    list.forEach((file) => {
        const fullPath = path.join(dir, file);
        const stat = fs.statSync(fullPath);
        if (stat && stat.isDirectory()) {
            results = results.concat(walk(fullPath));
        } else {
            if (fullPath.endsWith('.tsx') || fullPath.endsWith('.ts')) {
                results.push(fullPath);
            }
        }
    });
    return results;
}

const files = walk(targetDir);
let replacedCount = 0;

files.forEach(file => {
    let content = fs.readFileSync(file, 'utf8');

    // Replace API constant declaration
    // e.g. const API = `${process.env.NEXT_PUBLIC_API_URL}/api/admin`;
    let newContent = content.replace(/const\s+API\s*=\s*`\$\{process\.env\.NEXT_PUBLIC_API_URL\}\/api\/admin`;/g, "const API = '/api/admin';");

    // Replace inline fetch strings
    // e.g. `${process.env.NEXT_PUBLIC_API_URL}/api/...`
    newContent = newContent.replace(/\$\{process\.env\.NEXT_PUBLIC_API_URL\}\/api/g, '/api');

    if (content !== newContent) {
        fs.writeFileSync(file, newContent, 'utf8');
        replacedCount++;
        console.log('Updated: ' + file.replace(targetDir, ''));
    }
});

console.log(`\nReplacement complete! Updated ${replacedCount} files.`);

const fs = require('fs');
const path = require('path');

const directory = 't:\\USA\\crown\\frontend\\src';
const oldUrl = /http:\/\/localhost:5000/g;
const newUrl = 'https://usa-crown-back.vercel.app';

function walk(dir) {
    const files = fs.readdirSync(dir);
    files.forEach(file => {
        const filePath = path.join(dir, file);
        const stat = fs.statSync(filePath);
        if (stat.isDirectory()) {
            walk(filePath);
        } else if (stat.isFile()) {
            let content = fs.readFileSync(filePath, 'utf8');
            if (content.includes('localhost:5000')) {
                const newContent = content.replace(oldUrl, newUrl).replace(/localhost:5000/g, 'usa-crown-back.vercel.app');
                fs.writeFileSync(filePath, newContent, 'utf8');
                console.log(`Updated: ${filePath}`);
            }
        }
    });
}

walk(directory);

const fs = require('fs');
const path = require('path');

const directory = 't:\\USA\\crown\\frontend\\src';

function walk(dir) {
    const files = fs.readdirSync(dir);
    files.forEach(file => {
        const filePath = path.join(dir, file);
        const stat = fs.statSync(filePath);
        if (stat.isDirectory()) {
            walk(filePath);
        } else if (stat.isFile() && (filePath.endsWith('.tsx') || filePath.endsWith('.ts') || filePath.endsWith('.js') || filePath.endsWith('.jsx'))) {
            let content = fs.readFileSync(filePath, 'utf8');
            let modified = false;

            // Replace single/double quoted strings
            // Example: "https://usa-crown-back.vercel.app/api/foo" -> `${process.env.NEXT_PUBLIC_API_URL}/api/foo`
            const quoteRegex = /['"]https:\/\/usa-crown-back\.vercel\.app([^'"]*)['"]/g;
            if (quoteRegex.test(content)) {
                content = content.replace(quoteRegex, '`${process.env.NEXT_PUBLIC_API_URL}$1`');
                modified = true;
            }

            // Replace within existing template literals
            // Example: `https://usa-crown-back.vercel.app/api/foo/${id}` -> `${process.env.NEXT_PUBLIC_API_URL}/api/foo/${id}`
            const backtickRegex = /`https:\/\/usa-crown-back\.vercel\.app([^`]+)`/g;
            if (backtickRegex.test(content)) {
                content = content.replace(backtickRegex, '`${process.env.NEXT_PUBLIC_API_URL}$1`');
                modified = true;
            }

            // Also replace cases where the domain is hardcoded as a constant string not in a fetch
            // Example: const API = "https://usa-crown-back.vercel.app/api/admin";
            // The quoteRegex already covers this.

            if (modified) {
                fs.writeFileSync(filePath, content, 'utf8');
                console.log(`Updated: ${filePath}`);
            }
        }
    });
}

walk(directory);

