"use client";

import { useEffect, useState } from "react";
import styles from "../../profile/profile.module.css";

type PaymentMethod = {
  id: string;
  brand: string;
  last4: string;
  exp_month: number;
  exp_year: number;
  is_default: boolean;
};

export default function PaymentMethodsPage() {
  const [methods, setMethods] = useState<PaymentMethod[]>([]);
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState({ type: "", text: "" });

  const fetchMethods = async () => {
    try {
      const res = await fetch("/api/account/payment-methods");
      if (res.ok) {
        setMethods(await res.json());
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMethods();
  }, []);

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this payment method?")) return;
    try {
      const res = await fetch(`/api/account/payment-methods/${id}`, { method: "DELETE" });
      if (res.ok) {
        setMsg({ type: "success", text: "Payment method deleted." });
        setMethods(prev => prev.filter(m => m.id !== id));
      } else {
        setMsg({ type: "error", text: "Failed to delete payment method." });
      }
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div>
      <h2>Saved Payment Methods</h2>
      {msg.text && (
        <div className={msg.type === "error" ? styles.error : styles.success}>
          {msg.text}
        </div>
      )}

      {loading ? (
        <p>Loading...</p>
      ) : methods.length === 0 ? (
        <p>No saved payment methods found.</p>
      ) : (
        <div className={styles.addressList}>
          {methods.map(m => (
            <div key={m.id} className={styles.addressCard}>
              <h4>{m.brand.toUpperCase()} ending in {m.last4}</h4>
              <p>Expires: {m.exp_month.toString().padStart(2, '0')} / {m.exp_year}</p>
              {m.is_default && <span style={{ color: 'green', fontSize: '0.9rem', fontWeight: 'bold' }}>Default Method</span>}
              <div className={styles.addressActions}>
                <button onClick={() => handleDelete(m.id)} className={styles.btnSecondary} style={{color: 'red'}}>
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import styles from "./profile.module.css";
import { FiInfo } from "react-icons/fi";

export default function AccountProfilePage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ type: "", text: "" });

  const [profile, setProfile] = useState<any>(null);

  const [formData, setFormData] = useState({
    full_name: "",
    mobile: "",
    email: "" // Email is generally read-only for security, but we show it
  });

  useEffect(() => {
    fetch('/api/account/profile')
      .then(r => {
        if (!r.ok) throw new Error("Not logged in");
        return r.json();
      })
      .then(data => {
        setProfile(data);
        setFormData({
          full_name: data.full_name || "",
          mobile: data.mobile || "",
          email: data.email || ""
        });
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        window.location.href = '/login';
      });
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    setMsg({ type: "", text: "" });

    try {
      const res = await fetch('/api/account/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          full_name: formData.full_name,
          mobile: formData.mobile,
          email: formData.email
        })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Failed to update profile");

      setMsg({ type: "success", text: "Profile updated successfully." });
    } catch (err: any) {
      setMsg({ type: "error", text: err.message });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div>Loading profile...</div>;

  return (
    <div>
      <div className={styles.header}>
        <h1>Personal Profile</h1>
        <p>Manage your basic account details.</p>
      </div>

      {profile?.roles?.name && (
        <div className={styles.alert}>
          <FiInfo /> Account Type: {profile.roles.name}
        </div>
      )}

      {msg.text && (
        <div className={msg.type === 'error' ? styles.error : styles.success}>
          {msg.text}
        </div>
      )}

      <form onSubmit={handleSubmit} className={styles.form}>
        <div className={styles.formGroup}>
          <label>Username (Login ID)</label>
          <input type="text" className={styles.input} value={profile.username} disabled />
        </div>

        <div className={styles.formGroup}>
          <label>Full Name *</label>
          <input 
            required type="text" className={styles.input} 
            value={formData.full_name} 
            onChange={e => setFormData({...formData, full_name: e.target.value})}
          />
        </div>

        <div className={styles.formGroup}>
          <label>Email Address *</label>
          <input 
            required type="email" className={styles.input} 
            value={formData.email} 
            onChange={e => setFormData({...formData, email: e.target.value})}
          />
        </div>

        <div className={styles.formGroup}>
          <label>Mobile Number *</label>
          <input 
            required type="tel" className={styles.input} 
            value={formData.mobile} 
            onChange={e => setFormData({...formData, mobile: e.target.value})}
          />
        </div>

        <button type="submit" disabled={saving} className={styles.submitBtn}>
          {saving ? "Saving..." : "Save Changes"}
        </button>
      </form>
    </div>
  );
}

