"use client";

import { useEffect, useState } from "react";
import styles from "../addresses/addresses.module.css"; // Reuse modal and grid styles
import profileStyles from "../profile/profile.module.css";
import { FiPlus, FiUser } from "react-icons/fi";

export default function AccountUsersPage() {
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);

  const emptyForm = { full_name: "", email: "", mobile: "", password: "", is_active: true };
  const [formData, setFormData] = useState(emptyForm);

  const fetchUsers = async () => {
    try {
      const res = await fetch('/api/account/users');
      if (res.ok) setUsers(await res.json());
      setLoading(false);
    } catch (err) {
      console.error(err);
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const method = editId ? 'PUT' : 'POST';
      const url = editId ? `/api/account/users/${editId}` : '/api/account/users';

      const payload: any = {};
      if (!editId) {
        payload.full_name = formData.full_name;
        payload.email = formData.email;
        payload.mobile = formData.mobile;
        payload.password = formData.password;
      } else {
        payload.is_active = formData.is_active;
        if (formData.password) payload.new_password = formData.password;
      }

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      if (!res.ok) throw new Error("Failed to save user");

      setIsModalOpen(false);
      fetchUsers();
    } catch (err) {
      console.error(err);
      alert("Error saving sub-user");
    } finally {
      setSaving(false);
    }
  };

  const openNew = () => {
    setEditId(null);
    setFormData(emptyForm);
    setIsModalOpen(true);
  };

  const openEdit = (u: any) => {
    setEditId(u.id);
    setFormData({ ...emptyForm, full_name: u.full_name, email: u.email, is_active: u.is_active });
    setIsModalOpen(true);
  };

  if (loading) return <div>Loading sub-users...</div>;

  return (
    <div>
      <div className={profileStyles.header}>
        <h1>Sub-Users</h1>
        <p>Manage employees or staff who can access your account.</p>
      </div>

      <div className={styles.grid}>
        {users.map(u => (
          <div key={u.id} className={styles.card}>
            <span className={styles.defaultBadge} style={{background: u.is_active ? '#2e7d32' : '#c62828'}}>
              {u.is_active ? 'Active' : 'Disabled'}
            </span>
            <h3 style={{display:'flex', alignItems:'center', gap:'0.5rem'}}>
              <FiUser /> {u.full_name}
            </h3>
            <p>Username: {u.username}</p>
            <p>Email: {u.email}</p>
            <p>Role: {u.roles?.name || 'Sub User'}</p>

            <div className={styles.actions}>
              <button onClick={() => openEdit(u)} className={styles.actionBtn}>Manage Access</button>
            </div>
          </div>
        ))}

        <button className={styles.addBtn} onClick={openNew}>
          <FiPlus size={24} />
          <span>Add New Sub-User</span>
        </button>
      </div>

      {isModalOpen && (
        <div className={styles.modalOverlay}>
          <div className={styles.modal}>
            <h2>{editId ? 'Manage Sub-User' : 'Add Sub-User'}</h2>
            <form onSubmit={handleSubmit} className={styles.formGrid}>

              {!editId && (
                <>
                  <div className={styles.fullWidth}>
                    <label className={profileStyles.label}>Full Name *</label>
                    <input required type="text" className={profileStyles.input} value={formData.full_name} onChange={e => setFormData({...formData, full_name: e.target.value})} />
                  </div>
                  <div className={profileStyles.formGroup}>
                    <label>Email *</label>
                    <input required type="email" className={profileStyles.input} value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
                  </div>
                  <div className={profileStyles.formGroup}>
                    <label>Mobile *</label>
                    <input required type="tel" className={profileStyles.input} value={formData.mobile} onChange={e => setFormData({...formData, mobile: e.target.value})} />
                  </div>
                </>
              )}

              {editId && (
                <div className={styles.fullWidth}>
                  <p style={{margin:'0 0 1rem 0'}}><strong>{formData.full_name} ({formData.email})</strong></p>
                  <label className={styles.checkbox}>
                    <input type="checkbox" checked={formData.is_active} onChange={e => setFormData({...formData, is_active: e.target.checked})} />
                    Allow this user to log in
                  </label>
                </div>
              )}

              <div className={styles.fullWidth}>
                <label className={profileStyles.label}>{editId ? 'Reset Password (Optional)' : 'Initial Password *'}</label>
                <input required={!editId} type="password" placeholder="Minimum 6 characters" className={profileStyles.input} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
              </div>

              <div className={styles.fullWidth} style={{display: 'flex', gap: '1rem', marginTop: '1rem'}}>
                <button type="submit" disabled={saving} className={profileStyles.submitBtn}>{saving ? 'Saving...' : 'Save'}</button>
                <button type="button" onClick={() => setIsModalOpen(false)} className={profileStyles.input} style={{width: 'auto'}}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useState, useRef } from 'react';
import styles from './apply.module.css';
import { FiX } from 'react-icons/fi';



export default function ApplyPage() {
  const [step, setStep] = useState(1);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [errorField, setErrorField] = useState('');

  const firstNameRef = useRef<HTMLInputElement>(null);
  const lastNameRef = useRef<HTMLInputElement>(null);
  const emailRef = useRef<HTMLInputElement>(null);
  const hearAboutRef = useRef<HTMLSelectElement>(null);
  const passwordRef = useRef<HTMLInputElement>(null);
  const confirmPasswordRef = useRef<HTMLInputElement>(null);

  const companyNameRef = useRef<HTMLInputElement>(null);
  const companyWebsiteRef = useRef<HTMLInputElement>(null);
  const addressLineRef = useRef<HTMLInputElement>(null);
  const phoneRef = useRef<HTMLInputElement>(null);
  const resaleTaxIdRef = useRef<HTMLInputElement>(null);
  const cityRef = useRef<HTMLInputElement>(null);
  const zipCodeRef = useRef<HTMLInputElement>(null);
  const stateProvinceRef = useRef<HTMLInputElement>(null);
  const countryRef = useRef<HTMLInputElement>(null);
  const dropZoneRef = useRef<HTMLDivElement>(null);

  // Step 1: Personal Information
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [hearAbout, setHearAbout] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Step 2: Company Information
  const [companyName, setCompanyName] = useState('');
  const [companyWebsite, setCompanyWebsite] = useState('');
  const [addressLine, setAddressLine] = useState('');
  const [phone, setPhone] = useState('');
  const [resaleTaxId, setResaleTaxId] = useState('');
  const [city, setCity] = useState('');
  const [fax, setFax] = useState('');
  const [zipCode, setZipCode] = useState('');
  const [stateProvince, setStateProvince] = useState('');
  const [country, setCountry] = useState('');
  const [creditApp, setCreditApp] = useState('');

  // Step 3: Resale Certificate
  const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  // Form State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [submitSuccess, setSubmitSuccess] = useState(false);

  const handleNext = () => {
    if (step === 1) {
      if (!firstName.trim()) { setErrorField('firstName'); firstNameRef.current?.focus(); return; }
      if (!lastName.trim()) { setErrorField('lastName'); lastNameRef.current?.focus(); return; }
      if (!email.trim() || !/\S+@\S+\.\S+/.test(email.trim())) { setErrorField('email'); emailRef.current?.focus(); return; }
      if (!hearAbout) { setErrorField('hearAbout'); hearAboutRef.current?.focus(); return; }
      if (!password) { setErrorField('password'); passwordRef.current?.focus(); return; }
      if (!confirmPassword) { setErrorField('confirmPassword'); confirmPasswordRef.current?.focus(); return; }
    } else if (step === 2) {
      if (!companyName.trim()) { setErrorField('companyName'); companyNameRef.current?.focus(); return; }
      if (companyWebsite.trim() && !/^(https?:\/\/)?([\w\d\.-]+)\.([a-z\.]{2,6})(\/[\w\d\.-]*)*\/?$/i.test(companyWebsite.trim())) { setErrorField('companyWebsite'); companyWebsiteRef.current?.focus(); return; }
      if (!addressLine.trim()) { setErrorField('addressLine'); addressLineRef.current?.focus(); return; }
      if (!phone.trim()) { setErrorField('phone'); phoneRef.current?.focus(); return; }
      if (!resaleTaxId.trim()) { setErrorField('resaleTaxId'); resaleTaxIdRef.current?.focus(); return; }
      if (!city.trim()) { setErrorField('city'); cityRef.current?.focus(); return; }
      if (!zipCode.trim()) { setErrorField('zipCode'); zipCodeRef.current?.focus(); return; }
      if (!stateProvince.trim()) { setErrorField('stateProvince'); stateProvinceRef.current?.focus(); return; }
      if (!country) { setErrorField('country'); countryRef.current?.focus(); return; }
    }
    setErrorField('');
    if (step < 3) setStep(step + 1);
  };

  const handlePrev = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleFileDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const files = Array.from(e.dataTransfer.files).slice(0, 2);
    setUploadedFiles(files);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 2);
      setUploadedFiles(files);
    }
  };

  const removeFile = (index: number) => {
    setUploadedFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (uploadedFiles.length === 0) {
      setErrorField('certificates');
      setSubmitError('Please upload your signed resale certificate.');
      dropZoneRef.current?.focus();
      return;
    }
    setErrorField('');
    if (password !== confirmPassword) {
      setSubmitError('Passwords do not match');
      return;
    }

    setIsSubmitting(true);
    setSubmitError('');

    try {
      const formData = new FormData();
      formData.append('firstName', firstName);
      formData.append('lastName', lastName);
      formData.append('email', email);
      formData.append('hearAbout', hearAbout);
      formData.append('password', password);
      formData.append('companyName', companyName);
      formData.append('companyWebsite', companyWebsite);
      formData.append('addressLine', addressLine);
      formData.append('phone', phone);
      formData.append('resaleTaxId', resaleTaxId);
      formData.append('city', city);
      formData.append('fax', fax);
      formData.append('zipCode', zipCode);
      formData.append('stateProvince', stateProvince);
      formData.append('country', country);
      formData.append('creditApp', creditApp);

      uploadedFiles.forEach((file) => {
        formData.append('certificates', file);
      });

      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/register`, {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Failed to submit registration');
      }

      setSubmitSuccess(true);
    } catch (err: any) {
      setSubmitError(err.message || 'An error occurred during submission');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitSuccess) {
    return (
      <div className={styles.page}>
        <div className={styles.container}>
          <div className={styles.formCard} style={{ textAlign: 'center', padding: '4rem 2rem' }}>
            <h2 className={styles.stepTitle} style={{ color: 'green' }}>Registration Submitted!</h2>
            <p className={styles.stepDesc} style={{ marginTop: '1rem', fontSize: '1.1rem' }}>
              Your application has been received and is pending review. We will contact you once it is approved.
            </p>
            <Link href="/" className={styles.submitBtn} style={{ display: 'inline-block', marginTop: '2rem', textDecoration: 'none' }}>
              Return to Home
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className={styles.container}>
        {/* Step Indicator */}
        <div className={styles.stepIndicator}>
          <div className={`${styles.stepItem} ${step >= 1 ? styles.stepActive : ''} ${step > 1 ? styles.stepComplete : ''}`}>
            <div className={styles.stepNumber}>1</div>
            <span className={styles.stepLabel}>Personal Info</span>
          </div>
          <div className={styles.stepLine}></div>
          <div className={`${styles.stepItem} ${step >= 2 ? styles.stepActive : ''} ${step > 2 ? styles.stepComplete : ''}`}>
            <div className={styles.stepNumber}>2</div>
            <span className={styles.stepLabel}>Company Info</span>
          </div>
          <div className={styles.stepLine}></div>
          <div className={`${styles.stepItem} ${step >= 3 ? styles.stepActive : ''}`}>
            <div className={styles.stepNumber}>3</div>
            <span className={styles.stepLabel}>Resale Certificate</span>
          </div>
        </div>

        {/* Form Card */}
        <div className={styles.formCard}>
          <form className={styles.form} onSubmit={handleSubmit} noValidate>

            {/* ===== STEP 1: Personal Information ===== */}
            {step === 1 && (
              <div className={styles.stepContent}>
                <h2 className={styles.stepTitle}>Personal Information</h2>
                <p className={styles.stepDesc}>
                  Please fill out and submit the registration form to gain full access to the Crown Findings Co., INC Website.
                </p>

                <div className={styles.formGrid}>
                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Name <span className={styles.required}>*</span></label>
                    <div className={styles.nameRow}>
                      <div className={styles.nameField}>
                        <input
                          ref={firstNameRef}
                          type="text"
                          value={firstName}
                          onChange={(e) => setFirstName(e.target.value)}
                          className={`${styles.input} ${errorField === 'firstName' ? styles.errorBlink : ''}`}
                          onAnimationEnd={() => setErrorField('')}
                          placeholder="First name"
                          required
                        />
                        <span className={styles.fieldHint}>First</span>
                      </div>
                      <div className={styles.nameField}>
                        <input
                          ref={lastNameRef}
                          type="text"
                          value={lastName}
                          onChange={(e) => setLastName(e.target.value)}
                          className={`${styles.input} ${errorField === 'lastName' ? styles.errorBlink : ''}`}
                          onAnimationEnd={() => setErrorField('')}
                          placeholder="Last Name"
                          required
                        />
                        <span className={styles.fieldHint}>Last</span>
                      </div>
                    </div>
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Email <span className={styles.required}>*</span></label>
                    <input
                      ref={emailRef}
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className={`${styles.input} ${errorField === 'email' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Email"
                      required
                    />
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>How did you hear about us? <span className={styles.required}>*</span></label>
                    <select
                      ref={hearAboutRef}
                      value={hearAbout}
                      onChange={(e) => setHearAbout(e.target.value)}
                      className={`${styles.select} ${errorField === 'hearAbout' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      required
                    >
                      <option value="">How did you hear about us?</option>
                      <option value="google">Google Search</option>
                      <option value="referral">Referral</option>
                      <option value="tradeshow">Trade Show</option>
                      <option value="social">Social Media</option>
                      <option value="diamond-district">Diamond District Walk-in</option>
                      <option value="other">Other</option>
                    </select>
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Password <span className={styles.required}>*</span></label>
                    <input
                      ref={passwordRef}
                      type="password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className={`${styles.input} ${errorField === 'password' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Password"
                      required
                    />
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Confirm Password <span className={styles.required}>*</span></label>
                    <input
                      ref={confirmPasswordRef}
                      type="password"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      className={`${styles.input} ${errorField === 'confirmPassword' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Retype Password"
                      required
                    />
                  </div>
                </div>

                <div className={styles.btnRow}>
                  <button type="button" onClick={handleNext} className={styles.nextBtn}>
                    Next
                  </button>
                </div>
              </div>
            )}

            {/* ===== STEP 2: Company Information ===== */}
            {step === 2 && (
              <div className={styles.stepContent}>
                <h2 className={styles.stepTitle}>Company Information</h2>

                <div className={styles.formGrid}>
                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Company Name <span className={styles.required}>*</span></label>
                    <input
                      ref={companyNameRef}
                      type="text"
                      value={companyName}
                      onChange={(e) => setCompanyName(e.target.value)}
                      className={`${styles.input} ${errorField === 'companyName' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Company Name"
                      required
                    />
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Company Website</label>
                    <input
                      ref={companyWebsiteRef}
                      type="url"
                      value={companyWebsite}
                      onChange={(e) => setCompanyWebsite(e.target.value)}
                      className={`${styles.input} ${errorField === 'companyWebsite' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Company Website"
                    />
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Address Line <span className={styles.required}>*</span></label>
                    <input
                      ref={addressLineRef}
                      type="text"
                      value={addressLine}
                      onChange={(e) => setAddressLine(e.target.value)}
                      className={`${styles.input} ${errorField === 'addressLine' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Address Line"
                      required
                    />
                  </div>

                  <div className={styles.twoCol}>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>Phone <span className={styles.required}>*</span></label>
                      <input
                        ref={phoneRef}
                        type="tel"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        className={`${styles.input} ${errorField === 'phone' ? styles.errorBlink : ''}`}
                        onAnimationEnd={() => setErrorField('')}
                        placeholder="+1 (555) 123-4567"
                        required
                      />
                    </div>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>Fax</label>
                      <input
                        type="tel"
                        value={fax}
                        onChange={(e) => setFax(e.target.value)}
                        className={styles.input}
                        placeholder="Fax"
                      />
                    </div>
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Resale/Tax ID Number <span className={styles.required}>*</span></label>
                    <input
                      ref={resaleTaxIdRef}
                      type="text"
                      value={resaleTaxId}
                      onChange={(e) => setResaleTaxId(e.target.value)}
                      className={`${styles.input} ${errorField === 'resaleTaxId' ? styles.errorBlink : ''}`}
                      onAnimationEnd={() => setErrorField('')}
                      placeholder="Resale/Tax Id Number"
                      required
                    />
                  </div>

                  <div className={styles.twoCol}>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>City <span className={styles.required}>*</span></label>
                      <input
                        ref={cityRef}
                        type="text"
                        value={city}
                        onChange={(e) => setCity(e.target.value)}
                        className={`${styles.input} ${errorField === 'city' ? styles.errorBlink : ''}`}
                        onAnimationEnd={() => setErrorField('')}
                        placeholder="City"
                        required
                      />
                    </div>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>Postal / Zip Code <span className={styles.required}>*</span></label>
                      <input
                        ref={zipCodeRef}
                        type="text"
                        value={zipCode}
                        onChange={(e) => setZipCode(e.target.value)}
                        className={`${styles.input} ${errorField === 'zipCode' ? styles.errorBlink : ''}`}
                        onAnimationEnd={() => setErrorField('')}
                        placeholder="Postal / Zip Code"
                        required
                      />
                    </div>
                  </div>

                  <div className={styles.twoCol}>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>State / Province / Region <span className={styles.required}>*</span></label>
                      <input
                        ref={stateProvinceRef}
                        type="text"
                        value={stateProvince}
                        onChange={(e) => setStateProvince(e.target.value)}
                        className={`${styles.input} ${errorField === 'stateProvince' ? styles.errorBlink : ''}`}
                        onAnimationEnd={() => setErrorField('')}
                        placeholder="State / Province / Region"
                        required
                      />
                    </div>
                    <div className={styles.inputGroup}>
                      <label className={styles.label}>Country <span className={styles.required}>*</span></label>
                      <input
                        ref={countryRef}
                        type="text"
                        value={country}
                        onChange={(e) => setCountry(e.target.value)}
                        className={`${styles.input} ${errorField === 'country' ? styles.errorBlink : ''}`}
                        onAnimationEnd={() => setErrorField('')}
                        placeholder="Country"
                        required
                      />
                    </div>
                  </div>

                  <div className={styles.inputGroup}>
                    <label className={styles.label}>Credit Application <span className={styles.required}>*</span></label>
                    <div className={styles.radioGroup}>
                      <label className={styles.radioLabel}>
                        <input
                          type="radio"
                          name="creditApp"
                          value="yes"
                          checked={creditApp === 'yes'}
                          onChange={(e) => setCreditApp(e.target.value)}
                          className={styles.radio}
                        />
                        Yes, I also want to apply for credit application
                      </label>
                      <label className={styles.radioLabel}>
                        <input
                          type="radio"
                          name="creditApp"
                          value="no"
                          checked={creditApp === 'no'}
                          onChange={(e) => setCreditApp(e.target.value)}
                          className={styles.radio}
                        />
                        No, I don&#39;t want to apply for credit application
                      </label>
                    </div>
                  </div>
                </div>

                <div className={styles.btnRow}>
                  <button type="button" onClick={handlePrev} className={styles.prevBtn}>
                    Previous
                  </button>
                  <button type="button" onClick={handleNext} className={styles.nextBtn}>
                    Next
                  </button>
                </div>
              </div>
            )}

            {/* ===== STEP 3: Resale Certificate ===== */}
            {step === 3 && (
              <div className={styles.stepContent}>
                <h2 className={styles.stepTitle}>Resale Certificate</h2>
                <p className={styles.stepDesc}>
                  Please fill out and submit the registration form to gain full access to the Crown Findings Co., INC Website.
                </p>
                <div className={styles.certificateNotice}>
                  <p>
                    The New York State Resale Certificate ST-120 must be filled out, signed and submitted prior to the approval of your registration.
                  </p>
                </div>

                <Link
                  href="/NYS-ResaleCertificate-ST120.pdf"
                  target="_blank"
                  className={styles.downloadBtn}
                >
                  ↓ Download Resale Certificate
                </Link>

                <p className={styles.uploadInstructions}>
                  The Resale Certificate will open in a New Tab. Fill out the form and upload it back with your signature filled in.
                </p>

                <div className={styles.inputGroup}>
                  <label className={styles.label}>Upload Signed Certificate <span className={styles.required}>*</span></label>
                  <div
                    ref={dropZoneRef}
                    tabIndex={-1}
                    className={`${styles.dropZone} ${isDragging ? styles.dropZoneActive : ''} ${errorField === 'certificates' ? styles.errorBlink : ''}`}
                    onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                    onDragLeave={() => setIsDragging(false)}
                    onDrop={handleFileDrop}
                    onClick={() => fileInputRef.current?.click()}
                    onAnimationEnd={() => setErrorField('')}
                  >
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept=".pdf,.jpg,.jpeg,.png"
                      multiple
                      onChange={handleFileSelect}
                      className={styles.fileInput}
                    />
                    <div className={styles.dropIcon}>📄</div>
                    <p className={styles.dropText}>Drag &amp; Drop Files, or <span className={styles.browseLink}>Choose Files</span> to Upload</p>
                    <p className={styles.dropHint}>You can upload up to 2 files.</p>
                  </div>

                  {uploadedFiles.length > 0 && (
                    <div className={styles.fileList}>
                      {uploadedFiles.map((file, idx) => (
                        <div key={idx} className={styles.fileItem}>
                          <span className={styles.fileName}>📎 {file.name}</span>
                          <button type="button" onClick={() => removeFile(idx)} className={styles.removeFile}><FiX /></button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                <div className={styles.btnRow}>
                  <button type="button" onClick={handlePrev} className={styles.prevBtn}>
                    Previous
                  </button>
                  {submitError && <div className={styles.errorText} style={{ color: 'red', marginBottom: '1rem' }}>{submitError}</div>}
                  <button type="submit" className={styles.submitBtn} disabled={isSubmitting}>
                    {isSubmitting ? 'Submitting...' : 'Submit Registration Application'}
                  </button>
                </div>
              </div>
            )}

          </form>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import styles from '../blog.module.css';

// Fallback mock data for when API is unavailable
const fallbackData: Record<string, { title: string; date: string; image: string; content: string }> = {
  'the-essential-guide-to-jewelry-findings': {
    title: 'The Essential Guide to Jewelry Findings: What Every Jeweler Needs',
    date: 'October 12, 2023',
    image: 'https://images.unsplash.com/photo-1599643478514-411c7f558155?q=80&w=1200&auto=format&fit=crop',
    content: `
      <p>Whether you are a seasoned bench jeweler or just starting to design your own line, understanding the vast world of jewelry findings is absolutely essential. Findings are the building blocks of jewelry making—the functional components that hold pieces together, provide wearability, and often add that final touch of professionalism.</p>
      <h2>What Exactly Are Findings?</h2>
      <p>In the jewelry trade, "findings" refers to the components that go into the making of jewelry, excluding the gemstones and the primary metal stock (like sheet or wire). They are the clasps, the jump rings, the ear wires, the settings, and the bails.</p>
      <h2>Quality Matters</h2>
      <p>When it comes to fine jewelry, the quality of your findings reflects the quality of your brand. At Crown Findings, we pride ourselves on providing high-quality, durable findings manufactured to precise standards.</p>
    `
  }
};

interface BlogDetail {
  title: string;
  content: string;
  cover_image: string | null;
  published_at: string;
  excerpt: string;
  meta_description: string | null;
  author: string;
  tags: string[];
}

interface RelatedPost {
  title: string;
  slug: string;
  excerpt?: string;
  cover_image?: string;
  published_at?: string;
}

interface RelatedData {
  prev: { title: string; slug: string } | null;
  next: { title: string; slug: string } | null;
  similar: RelatedPost[];
}

async function getBlogPost(slug: string): Promise<BlogDetail | null> {
  try {
    const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/blogs/${slug}`, {
      cache: 'no-store'
    });
    if (!res.ok) return null;
    const data = await res.json();
    return data.blog || null;
  } catch {
    return null;
  }
}

async function getRelatedPosts(slug: string): Promise<RelatedData | null> {
  try {
    const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/blogs/${slug}/related`, {
      cache: 'no-store'
    });
    if (!res.ok) return null;
    const data = await res.json();
    return data;
  } catch {
    return null;
  }
}

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }) {
  const resolvedParams = await params;
  const post = await getBlogPost(resolvedParams.slug);

  if (post) {
    return {
      title: `${post.title} | Crown Findings`,
      description: post.meta_description || post.excerpt || ''
    };
  }

  // Fallback
  const fallback = fallbackData[resolvedParams.slug];
  if (fallback) return { title: `${fallback.title} | Crown Findings` };

  return { title: 'Post Not Found' };
}

export default async function BlogPostPage({ params }: { params: Promise<{ slug: string }> }) {
  const resolvedParams = await params;
  const post = await getBlogPost(resolvedParams.slug);
  const related = await getRelatedPosts(resolvedParams.slug);

  // If API returned data
  if (post) {
    const dateStr = new Date(post.published_at).toLocaleDateString('en-US', {
      month: 'long', day: 'numeric', year: 'numeric'
    });

    return (
      <main className={styles.main}>
        <section className={styles.postContainer}>
          <Link href="/blog" className={styles.backLink}>&larr; Back to Blog</Link>

          <div className={styles.postHeader}>
            <span className={styles.postDate}>{dateStr}</span>
            <h1 className={styles.postTitle}>{post.title}</h1>
          </div>

          {post.cover_image && (
            <img src={post.cover_image} alt={post.title} className={styles.postHeroImage} />
          )}

          <div
            className={styles.postContent}
            dangerouslySetInnerHTML={{ __html: post.content }}
          />

          {/* Prev / Next Navigation */}
          {related && (related.prev || related.next) && (
            <nav className={styles.postNav}>
              <div className={styles.postNavItem}>
                {related.prev && (
                  <Link href={`/blog/${related.prev.slug}`} className={styles.postNavLink}>
                    <span className={styles.postNavLabel}>&larr; Previous</span>
                    <span className={styles.postNavTitle}>{related.prev.title}</span>
                  </Link>
                )}
              </div>
              <div className={`${styles.postNavItem} ${styles.postNavItemNext}`}>
                {related.next && (
                  <Link href={`/blog/${related.next.slug}`} className={styles.postNavLink}>
                    <span className={styles.postNavLabel}>Next &rarr;</span>
                    <span className={styles.postNavTitle}>{related.next.title}</span>
                  </Link>
                )}
              </div>
            </nav>
          )}

          {/* Similar Posts */}
          {related && related.similar.length > 0 && (
            <section className={styles.similarSection}>
              <h2 className={styles.similarTitle}>You May Also Like</h2>
              <div className={styles.similarGrid}>
                {related.similar.map((s) => (
                  <Link key={s.slug} href={`/blog/${s.slug}`} className={styles.similarCard}>
                    {s.cover_image && (
                      <img src={s.cover_image} alt={s.title} className={styles.similarImage} />
                    )}
                    <div className={styles.similarContent}>
                      <h3 className={styles.similarCardTitle}>{s.title}</h3>
                      {s.excerpt && <p className={styles.similarExcerpt}>{s.excerpt}</p>}
                    </div>
                  </Link>
                ))}
              </div>
            </section>
          )}
        </section>
      </main>
    );
  }

  // Fallback to static data
  const fallback = fallbackData[resolvedParams.slug];
  if (!fallback) {
    notFound();
  }

  return (
    <main className={styles.main}>
      <section className={styles.postContainer}>
        <Link href="/blog" className={styles.backLink}>&larr; Back to Blog</Link>

        <div className={styles.postHeader}>
          <span className={styles.postDate}>{fallback.date}</span>
          <h1 className={styles.postTitle}>{fallback.title}</h1>
        </div>

        <img src={fallback.image} alt={fallback.title} className={styles.postHeroImage} />

        <div
          className={styles.postContent}
          dangerouslySetInnerHTML={{ __html: fallback.content }}
        />
      </section>
    </main>
  );
}

"use client";

import React, { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import styles from './blog.module.css';
import { FiSearch, FiX } from 'react-icons/fi';

interface BlogPost {
  slug: string;
  title: string;
  excerpt: string;
  published_at: string;
  cover_image: string | null;
  category?: string | null;
}

export default function BlogPage() {
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [categories, setCategories] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter state
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('');
  const [searchTimeout, setSearchTimeout] = useState<NodeJS.Timeout | null>(null);

  const fetchPosts = useCallback(async (search: string, category: string) => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set('limit', '50');
      if (search) params.set('search', search);
      if (category) params.set('category', category);

      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/blogs?${params.toString()}`);
      if (res.ok) {
        const data = await res.json();
        setPosts(data.blogs || []);
      }
    } catch {
      // keep existing posts
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    // Initial fetch
    fetchPosts('', '');

    // Fetch categories
    async function fetchCategories() {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/blogs/categories`);
        if (res.ok) {
          const data = await res.json();
          setCategories(data.categories || []);
        }
      } catch {
        // silent
      }
    }
    fetchCategories();
  }, [fetchPosts]);

  // Debounced search
  const handleSearchChange = (value: string) => {
    setSearchQuery(value);
    if (searchTimeout) clearTimeout(searchTimeout);
    const timeout = setTimeout(() => {
      fetchPosts(value, activeCategory);
    }, 400);
    setSearchTimeout(timeout);
  };

  const handleCategoryClick = (cat: string) => {
    const newCat = activeCategory === cat ? '' : cat;
    setActiveCategory(newCat);
    fetchPosts(searchQuery, newCat);
  };

  const clearFilters = () => {
    setSearchQuery('');
    setActiveCategory('');
    fetchPosts('', '');
  };

  const hasFilters = searchQuery || activeCategory;

  return (
    <main className={styles.main}>
      <section className={styles.heroSection}>
        <div className={styles.heroContent}>
          <h1 className={styles.heroTitle}>The Crown Blog</h1>
        </div>
      </section>

      <section className={styles.blogLayout}>
        {/* Left Sidebar — fixed */}
        <aside className={styles.blogSidebar}>
          <div className={styles.sidebarInner}>
            {/* Search */}
            <div className={styles.sidebarSection}>
              <h3 className={styles.sidebarTitle}>Search</h3>
              <div className={styles.searchBox}>
                <FiSearch className={styles.searchIcon} />
                <input
                  type="text"
                  className={styles.searchInput}
                  placeholder="Search articles..."
                  value={searchQuery}
                  onChange={(e) => handleSearchChange(e.target.value)}
                />
                {searchQuery && (
                  <button
                    className={styles.searchClear}
                    onClick={() => handleSearchChange('')}
                    aria-label="Clear search"
                  >
                    <FiX />
                  </button>
                )}
              </div>
            </div>

            {/* Categories */}
            {categories.length > 0 && (
              <div className={styles.sidebarSection}>
                <h3 className={styles.sidebarTitle}>Categories</h3>
                <ul className={styles.categoryList}>
                  {categories.map((cat) => (
                    <li key={cat}>
                      <button
                        className={`${styles.categoryBtn} ${activeCategory === cat ? styles.categoryBtnActive : ''}`}
                        onClick={() => handleCategoryClick(cat)}
                      >
                        {cat}
                      </button>
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {/* Active Filters */}
            {hasFilters && (
              <div className={styles.sidebarSection}>
                <button className={styles.clearFiltersBtn} onClick={clearFilters}>
                  <FiX /> Clear All Filters
                </button>
              </div>
            )}
          </div>
        </aside>

        {/* Right Content — scrollable blog list */}
        <div className={styles.blogMain}>
          {loading ? (
            <div className={styles.blogLoading}>Loading articles...</div>
          ) : posts.length === 0 ? (
            <div className={styles.blogEmpty}>
              <h3>No articles found</h3>
              <p>Try adjusting your search or category filter.</p>
              {hasFilters && (
                <button className={styles.clearFiltersBtn} onClick={clearFilters} style={{ marginTop: '1rem' }}>
                  Clear Filters
                </button>
              )}
            </div>
          ) : (
            <>
              {hasFilters && (
                <p className={styles.resultCount}>
                  Showing {posts.length} article{posts.length !== 1 ? 's' : ''}
                  {activeCategory && <> in <strong>{activeCategory}</strong></>}
                  {searchQuery && <> matching &quot;<strong>{searchQuery}</strong>&quot;</>}
                </p>
              )}
              <div className={styles.blogGrid}>
                {posts.map((post) => {
                  const dateStr = new Date(post.published_at).toLocaleDateString('en-US', {
                    month: 'long', day: 'numeric', year: 'numeric'
                  });
                  return (
                    <Link href={`/blog/${post.slug}`} key={post.slug} className={styles.blogCard}>
                      {post.cover_image && (
                        <img src={post.cover_image} alt={post.title} className={styles.blogImage} />
                      )}
                      <div className={styles.blogCardContent}>
                        {post.category && (
                          <span className={styles.blogCategory}>{post.category}</span>
                        )}
                        <span className={styles.blogDate}>{dateStr}</span>
                        <h2 className={styles.blogCardTitle}>{post.title}</h2>
                        <p className={styles.blogCardExcerpt}>{post.excerpt}</p>
                        <span className={styles.readMore}>Read Article &rarr;</span>
                      </div>
                    </Link>
                  );
                })}
              </div>
            </>
          )}
        </div>
      </section>
    </main>
  );
}

