'use client';

import { useState, useEffect, useCallback, Suspense } from 'react';
import Link from 'next/link';
import { useSearchParams, useRouter, usePathname } from 'next/navigation';
import { FiMenu, FiX, FiSearch } from 'react-icons/fi';
import styles from './products.module.css';

interface Product {
  id: number;
  name: string;
  slug: string;
  sku: string;
  type: string;
  image: string | null;
  metalTypes: string[];
  tags?: { id: number; name: string }[];
  sizeRanges?: { name: string; range: string }[];
  priceRange?: string | null;
}

interface AttributeTerm {
  id: number;
  name: string;
  slug: string;
  color_hex?: string;
  image_url?: string;
}

interface DynamicFilter {
  id: number;
  name: string;
  slug: string;
  type: string;
  terms: AttributeTerm[];
}

interface CategoryTree {
  id: number;
  name: string;
  slug: string;
  children: CategoryTree[];
}

function ProductsContent() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const categoryParam = searchParams.get('category');
  const metalParam = searchParams.get('metal');

  const [products, setProducts] = useState<Product[]>([]);
  const [filters, setFilters] = useState<DynamicFilter[]>([]);

  // Parse initial selected attributes from URL
  const initialSelectedAttrs: Record<string, string[]> = {};
  for (const [key, val] of searchParams.entries()) {
    if (key.startsWith('attr_') && val) {
      initialSelectedAttrs[key.replace('attr_', '')] = val.split(',');
    }
  }

  const [selectedAttributes, setSelectedAttributes] = useState<Record<string, string[]>>(initialSelectedAttrs);
  const [categories, setCategories] = useState<CategoryTree[]>([]);
  const [allMetalTypes, setAllMetalTypes] = useState<string[]>([]);
  const [metalColorMap, setMetalColorMap] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);

  const [sortBy, setSortBy] = useState('name');
  const searchParamVal = searchParams.get('search') || '';
  const [searchQuery, setSearchQuery] = useState(searchParamVal);
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchParamVal);
  const [selectedCategories, setSelectedCategories] = useState<string[]>(
    categoryParam ? categoryParam.split(',') : []
  );
  const [selectedMetals, setSelectedMetals] = useState<string[]>(
    metalParam ? metalParam.split(',') : []
  );
  const [mobileSidebar, setMobileSidebar] = useState(false);

  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);

  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Check user session on mount
  useEffect(() => {
    async function checkSession() {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/user/session`, {
          credentials: 'include',
        });
        if (res.ok) {
          const data = await res.json();
          if (data.authenticated) {
            setIsAuthenticated(true);
          }
        }
      } catch {
        // silently fail
      }
    }
    checkSession();
  }, []);

  // Fetch categories on mount
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/categories`);
        const data = await res.json();
        setCategories(data.categories || []);
      } catch (err) {
        console.error('Failed to fetch categories', err);
      }
    };
    fetchCategories();
  }, []);

  // Fetch attribute filters
  useEffect(() => {
    const fetchFilters = async () => {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/products/filters`);
        const data = await res.json();
        setAllMetalTypes(data.metalTypes || []);
        setMetalColorMap(data.metalColors || {});
        setFilters(data.filters || []);
      } catch (err) {
        console.error('Failed to fetch product filters', err);
      }
    };
    fetchFilters();
  }, []);

  // Sync URL params to state
  useEffect(() => {
    setSelectedCategories(categoryParam ? categoryParam.split(',') : []);
    setSelectedMetals(metalParam ? metalParam.split(',') : []);
    const s = searchParams.get('search') || '';
    setSearchQuery(s);
    setDebouncedSearchQuery(s);
    setPage(1);
  }, [categoryParam, metalParam, searchParams]);

  // Fetch products
  const fetchProducts = useCallback(async (
    p: number,
    search: string,
    sort: string,
    categorySlugs: string[],
    metalTypes: string[],
    attrs: Record<string, string[]>,
    signal?: AbortSignal
  ) => {
    try {
      const params = new URLSearchParams({ page: String(p), limit: '24', sort });
      if (search) params.set('search', search);
      if (categorySlugs.length > 0) params.set('category', categorySlugs.join(','));
      if (metalTypes.length > 0) params.set('metal', metalTypes.join(','));
      Object.entries(attrs).forEach(([slug, values]) => {
        if (Array.isArray(values) && values.length > 0) params.set(`attr_${slug}`, values.join(','));
      });

      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/products?${params}`, { signal });
      const data = await res.json();

      if (signal?.aborted) return;

      setProducts(data.products || []);
      setTotalPages(data.totalPages || 1);
      setTotal(data.total || 0);
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') return;
      console.error('Failed to fetch products', err);
    } finally {
      if (signal?.aborted) return;
      setLoading(false);
    }
  }, []);

  // Debounce search
  useEffect(() => {
    const timeout = setTimeout(() => {
      setDebouncedSearchQuery(searchQuery);
      setPage(1);
    }, 400);
    return () => clearTimeout(timeout);
  }, [searchQuery]);

  // Trigger fetch
  useEffect(() => {
    const controller = new AbortController();
    const timeout = setTimeout(() => {
      fetchProducts(page, debouncedSearchQuery, sortBy, selectedCategories, selectedMetals, selectedAttributes, controller.signal);
    }, 0);
    return () => {
      clearTimeout(timeout);
      controller.abort();
    };
  }, [page, debouncedSearchQuery, sortBy, selectedCategories, selectedMetals, selectedAttributes, fetchProducts]);

  const handleSearch = (val: string) => {
    setSearchQuery(val);
    setLoading(true);
  };

  const updateUrlParams = (cats: string[], attrs: Record<string, string[]>) => {
    const params = new URLSearchParams(searchParams.toString());
    if (cats.length > 0) params.set('category', cats.join(','));
    else params.delete('category');
    const keys = Array.from(params.keys());
    keys.forEach(k => { if (k.startsWith('attr_')) params.delete(k); });
    params.delete('metal');
    Object.entries(attrs).forEach(([slug, values]) => {
      if (values.length > 0) params.set(`attr_${slug}`, values.join(','));
    });
    router.replace(`${pathname}?${params.toString()}`, { scroll: false });
  };

  const toggleCategory = (slug: string, childSlugs: string[] = []) => {
    setLoading(true);
    let newCats: string[];
    if (selectedCategories.includes(slug)) {
      newCats = selectedCategories.filter(c => c !== slug && !childSlugs.includes(c));
    } else {
      newCats = [...selectedCategories, slug];
    }
    setSelectedCategories(newCats);
    updateUrlParams(newCats, selectedAttributes);
    setPage(1);
  };

  const toggleSubcategory = (slug: string) => {
    setLoading(true);
    let newCats: string[];
    if (selectedCategories.includes(slug)) {
      newCats = selectedCategories.filter(c => c !== slug);
    } else {
      newCats = [...selectedCategories, slug];
    }
    setSelectedCategories(newCats);
    updateUrlParams(newCats, selectedAttributes);
    setPage(1);
  };

  const getCategoryDescendantSlugs = (category: CategoryTree): string[] =>
    category.children.flatMap(child => [child.slug, ...getCategoryDescendantSlugs(child)]);

  const getCategoryName = (slug: string) => {
    let foundName = slug;
    const findInTree = (nodes: CategoryTree[]) => {
      for (const node of nodes) {
        if (node.slug === slug) foundName = node.name;
        if (node.children) findInTree(node.children);
      }
    };
    findInTree(categories);
    return foundName;
  };

  const renderCategoryFilter = (category: CategoryTree) => {
    const childSlugs = getCategoryDescendantSlugs(category);
    const isParentSelected = selectedCategories.includes(category.slug);
    return (
      <div key={category.id} className={styles.categoryItem}>
        <label className={styles.checkLabel}>
          <input
            type="checkbox"
            checked={isParentSelected}
            onChange={() => (
              childSlugs.length > 0
                ? toggleCategory(category.slug, childSlugs)
                : toggleSubcategory(category.slug)
            )}
            className={styles.checkInput}
          />
          {category.name}
        </label>
        {category.children.length > 0 && (
          <div className={styles.subcategories}>
            {category.children.map(renderCategoryFilter)}
          </div>
        )}
      </div>
    );
  };

  const toggleAttribute = (attrSlug: string, termName: string) => {
    setLoading(true);
    const current = selectedAttributes[attrSlug] || [];
    const updated = current.includes(termName)
      ? current.filter(t => t !== termName)
      : [...current, termName];
    const next = { ...selectedAttributes };
    if (updated.length > 0) next[attrSlug] = updated;
    else delete next[attrSlug];

    setSelectedAttributes(next);
    updateUrlParams(selectedCategories, next);
    setPage(1);
  };

  const toggleMetal = (metal: string) => {
    setLoading(true);
    let newMetals: string[];
    if (selectedMetals.includes(metal)) {
      newMetals = selectedMetals.filter(m => m !== metal);
    } else {
      newMetals = [...selectedMetals, metal];
    }
    setSelectedMetals(newMetals);
    updateUrlParams(selectedCategories, selectedAttributes);
    setPage(1);
  };

  const resetFilters = () => {
    setLoading(true);
    setSelectedCategories([]);
    setSelectedMetals([]);
    setSearchQuery('');
    setDebouncedSearchQuery('');
    setPage(1);
    updateUrlParams([], {});
  };

  return (
    <div className={styles.page}>
      <div className={styles.layout}>

        {/* Mobile filter toggle */}
        <button className={styles.mobileFilterBtn} onClick={() => setMobileSidebar(!mobileSidebar)}>
          <FiMenu style={{ marginRight: '8px' }} /> Filters
        </button>

        {/* Sidebar */}
        <aside className={`${styles.sidebar} ${mobileSidebar ? styles.sidebarOpen : ''}`}>
          <button className={styles.mobileClose} onClick={() => setMobileSidebar(false)}>
            <FiX style={{ marginRight: '8px' }} /> Close
          </button>

          <div className={styles.searchBox}>
            <input
              type="text"
              placeholder="Search Product..."
              value={searchQuery}
              onChange={(e) => handleSearch(e.target.value)}
              className={styles.searchInput}
            />
            <span className={styles.searchIcon}>
              <FiSearch />
            </span>
          </div>

          {/* Categories */}
          <div className={styles.filterBlock}>
            <h3 className={styles.filterTitle}>Categories</h3>
            <div className={styles.filterList}>
              {categories.map(renderCategoryFilter)}
            </div>
          </div>

          {/* Metal Type */}
          <div className={styles.filterBlock}>
            <h3 className={styles.filterTitle}>Metal Type</h3>
            <div className={styles.filterList}>
              {allMetalTypes.map(metal => (
                <label key={metal} className={styles.checkLabel}>
                  <input
                    type="checkbox"
                    checked={selectedMetals.includes(metal)}
                    onChange={() => toggleMetal(metal)}
                    className={styles.checkInput}
                  />
                  {metal}
                </label>
              ))}
            </div>
          </div>

          {/* Dynamic attribute filters */}
          {filters.map(filter => (
            <div key={filter.id} className={styles.filterBlock}>
              <h3 className={styles.filterTitle}>{filter.name}</h3>
              <div className={styles.filterList}>
                {filter.terms.map(term => (
                  <label key={term.id} className={styles.checkLabel}>
                    <input
                      type="checkbox"
                      checked={(selectedAttributes[filter.slug] || []).includes(term.name)}
                      onChange={() => toggleAttribute(filter.slug, term.name)}
                      className={styles.checkInput}
                    />
                    {term.color_hex && (
                      <span style={{ display: 'inline-block', width: 12, height: 12, borderRadius: '50%', background: term.color_hex, marginRight: 4, border: '1px solid #ccc' }} />
                    )}
                    {term.name}
                  </label>
                ))}
              </div>
            </div>
          ))}
        </aside>

        {/* Main Content */}
        <main className={styles.main}>
          {/* Top Bar */}
          <div className={styles.topBar}>
            <div className={styles.activeFiltersGroup}>
              <button onClick={resetFilters} className={styles.resetBtn}>Reset Filters</button>

              {searchQuery && (
                <span className={styles.activeFilterTag}>
                  Search: {searchQuery}
                  <button className={styles.activeFilterRemoveBtn} onClick={() => {
                    setSearchQuery('');
                    const params = new URLSearchParams(searchParams.toString());
                    params.delete('search');
                    router.replace(`${pathname}?${params.toString()}`, { scroll: false });
                  }}><FiX /></button>
                </span>
              )}

              {selectedCategories.map(cat => (
                <span key={cat} className={styles.activeFilterTag}>
                  {getCategoryName(cat)}
                  <button className={styles.activeFilterRemoveBtn} onClick={() => toggleSubcategory(cat)}><FiX /></button>
                </span>
              ))}

              {Object.entries(selectedAttributes).map(([slug, values]) =>
                values.map(val => {
                  const filterName = filters.find(f => f.slug === slug)?.name || slug;
                  return (
                    <span key={`${slug}-${val}`} className={styles.activeFilterTag}>
                      {filterName}: {val}
                      <button className={styles.activeFilterRemoveBtn} onClick={() => toggleAttribute(slug, val)}><FiX /></button>
                    </span>
                  );
                })
              )}
            </div>

            <span className={styles.resultCount}>
              Showing {products.length} of {total.toLocaleString()} results
            </span>
            <select
              value={sortBy}
              onChange={(e) => { setLoading(true); setSortBy(e.target.value); setPage(1); }}
              className={styles.sortSelect}
            >
              <option value="name">Sort by Name</option>
              <option value="newest">Sort by Newest</option>
            </select>
          </div>

          {/* Product Grid */}
          {loading ? (
            <div style={{ padding: '3rem', textAlign: 'center', color: '#888' }}>
              Loading products...
            </div>
          ) : (
            <div className={styles.productGrid}>
              {products.map(product => (
                <div key={product.id} className={styles.productCard}>
                  <div className={styles.productImageWrap}>
                    {product.tags && product.tags.length > 0 && (
                      <div style={{ position: 'absolute', top: 10, left: 10, zIndex: 10, display: 'flex', flexDirection: 'column', gap: 5 }}>
                        {product.tags.map((t) => (
                          <span key={t.id} style={{ background: '#111', color: '#fff', padding: '4px 8px', fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', borderRadius: 4 }}>
                            {t.name}
                          </span>
                        ))}
                      </div>
                    )}
                    <img
                      src={product.image || '/web-phts/a-17.jpg'}
                      alt={product.name}
                      className={styles.productImage}
                    />
                  </div>
                  <div className={styles.productInfo}>
                    <h3 className={styles.productName}>{product.name}</h3>
                    <div className={styles.metalRow}>
                      <span className={styles.metalLabel}>Metal Type:</span>
                      <div className={styles.metalDots}>
                        {(product.metalTypes || []).map(m => (
                          <span
                            key={m}
                            className={styles.metalDot}
                            style={
                              metalColorMap[m]
                                ? { backgroundColor: metalColorMap[m] }
                                : { background: 'transparent', backgroundImage: 'linear-gradient(to bottom right, transparent 45%, #d0d5dd 45%, #d0d5dd 55%, transparent 55%)', border: '1px solid #d0d5dd' }
                            }
                            title={m}
                          ></span>
                        ))}
                      </div>
                    </div>
                    {product.sizeRanges && product.sizeRanges.map((sz, i) => (
                      <div key={i} className={styles.metalRow}>
                        <span className={styles.metalLabel}>{sz.name}:</span>
                        <span className={styles.metalValue}>{sz.range}</span>
                      </div>
                    ))}
                    {isAuthenticated && product.priceRange && (
                      <div className={styles.metalRow}>
                        <span className={styles.metalLabel}>Price:</span>
                        <span className={styles.priceValue}>{product.priceRange}</span>
                      </div>
                    )}
                  </div>
                  <Link href={`/products/${product.id}`} className={styles.viewBtn}>
                    View Details
                  </Link>
                </div>
              ))}
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem', padding: '2rem 0', flexWrap: 'wrap' }}>
              <button
                onClick={() => { setLoading(true); setPage(p => Math.max(1, p - 1)); }}
                disabled={page <= 1}
                style={{ padding: '0.5rem 1rem', border: '1px solid #d0d5dd', background: page <= 1 ? '#f4f6f8' : '#fff', cursor: page <= 1 ? 'not-allowed' : 'pointer', fontFamily: 'inherit' }}
              >
                ← Previous
              </button>
              <span style={{ padding: '0.5rem 1rem', color: '#666', fontSize: '0.9rem' }}>
                Page {page} of {totalPages}
              </span>
              <button
                onClick={() => { setLoading(true); setPage(p => Math.min(totalPages, p + 1)); }}
                disabled={page >= totalPages}
                style={{ padding: '0.5rem 1rem', border: '1px solid #d0d5dd', background: page >= totalPages ? '#f4f6f8' : '#fff', cursor: page >= totalPages ? 'not-allowed' : 'pointer', fontFamily: 'inherit' }}
              >
                Next →
              </button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

export default function ProductsPage() {
  return (
    <Suspense fallback={<div style={{ padding: '3rem', textAlign: 'center', color: '#888' }}>Loading products...</div>}>
      <ProductsContent />
    </Suspense>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import styles from './profile.module.css';
import { FiDownload, FiShoppingBag, FiPlus } from 'react-icons/fi';

interface UserProfile {
  id: string;
  username: string;
  email: string;
  full_name: string;
  mobile: string;
  created_at: string;
  roles: { name: string }[];
}

interface CompanyProfile {
  company_name: string;
  company_address: string;
  company_phone: string;
  website: string;
  tax_id: string;
  resale_certificate_url: string;
}

interface SubUser {
  id: string;
  username: string;
  email: string;
  full_name: string;
  mobile: string;
  is_active: boolean;
  created_at: string;
  roles: { name: string }[];
}

export default function ProfilePage() {
  const router = useRouter();

  const [activeTab, setActiveTab] = useState<'personal' | 'company' | 'subusers'>('personal');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Personal Form
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [fullName, setFullName] = useState('');
  const [mobile, setMobile] = useState('');
  const [email, setEmail] = useState('');

  // Company Form
  const [company, setCompany] = useState<CompanyProfile | null>(null);
  const [companyName, setCompanyName] = useState('');
  const [companyWebsite, setCompanyWebsite] = useState('');
  const [companyAddress, setCompanyAddress] = useState('');
  const [companyPhone, setCompanyPhone] = useState('');

  // Sub-users
  const [subUsers, setSubUsers] = useState<SubUser[]>([]);
  const [newSubUserName, setNewSubUserName] = useState('');
  const [newSubUserEmail, setNewSubUserEmail] = useState('');
  const [newSubUserMobile, setNewSubUserMobile] = useState('');
  const [newSubUserPassword, setNewSubUserPassword] = useState('');

  useEffect(() => {
    async function fetchData() {
      try {
        const [profileRes, companyRes, usersRes] = await Promise.all([
          fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/profile`, { credentials: 'include' }),
          fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/company`, { credentials: 'include' }),
          fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/users`, { credentials: 'include' }).catch(() => null)
        ]);

        if (profileRes.status === 401) {
          router.push('/login');
          return;
        }

        if (profileRes.ok) {
          const data = await profileRes.json();
          setProfile(data);
          setFullName(data.full_name || '');
          setMobile(data.mobile || '');
          setEmail(data.email || '');
        }

        if (companyRes.ok) {
          const cData = await companyRes.json();
          setCompany(cData);
          setCompanyName(cData.company_name || '');
          setCompanyWebsite(cData.website || '');
          setCompanyAddress(cData.company_address || '');
          setCompanyPhone(cData.company_phone || '');
        }

        if (usersRes && usersRes.ok) {
          const uData = await usersRes.json();
          if (Array.isArray(uData)) setSubUsers(uData);
        }

      } catch (err: any) {
        setError('Failed to load profile data.');
      } finally {
        setLoading(false);
      }
    }
    fetchData();
  }, [router]);

  const handleSavePersonal = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true); setError(''); setSuccess('');
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/profile`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ full_name: fullName, mobile }),
        credentials: 'include',
      });
      if (!res.ok) throw new Error('Failed to update profile');
      setSuccess('Profile updated successfully!');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleSaveCompany = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true); setError(''); setSuccess('');
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/company`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          company_name: companyName,
          website: companyWebsite,
          company_address: companyAddress,
          company_phone: companyPhone
        }),
        credentials: 'include',
      });
      if (!res.ok) throw new Error('Failed to update company. Sub-users cannot update company profile.');
      setSuccess('Company info updated successfully!');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleAddSubUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true); setError(''); setSuccess('');
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/users`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          full_name: newSubUserName,
          email: newSubUserEmail,
          mobile: newSubUserMobile,
          password: newSubUserPassword
        }),
        credentials: 'include',
      });
      if (!res.ok) throw new Error('Failed to create sub-user. Sub-users cannot create other users.');
      const data = await res.json();
      setSubUsers([...subUsers, data]);
      setSuccess('Sub-user created successfully!');
      setNewSubUserName(''); setNewSubUserEmail(''); setNewSubUserMobile(''); setNewSubUserPassword('');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleToggleSubUser = async (id: string, currentStatus: boolean) => {
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/account/users/${id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ is_active: !currentStatus }),
        credentials: 'include',
      });
      if (res.ok) {
        setSubUsers(subUsers.map(u => u.id === id ? { ...u, is_active: !currentStatus } : u));
      }
    } catch (err) {
      console.error(err);
    }
  };

  if (loading) {
    return (
      <div className={styles.page}>
        <div className={styles.container}>
          <p style={{ textAlign: 'center', padding: '4rem', fontWeight: 600 }}>Loading profile...</p>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className={styles.container}>
        <div className={styles.header} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h1 className={styles.title}>My Account</h1>
            <p className={styles.subtitle}>Manage your details, company, and team.</p>
          </div>
          <Link href="/orders" style={{
            display: 'flex', alignItems: 'center', gap: '0.5rem',
            backgroundColor: '#000', color: '#fff', padding: '0.5rem 1rem',
            borderRadius: '4px', textDecoration: 'none', fontWeight: 600
          }}>
            <FiShoppingBag /> My Orders
          </Link>
        </div>

        {error && <div className={styles.alert} style={{ backgroundColor: '#f8d7da', color: '#721c24', borderLeftColor: '#dc3545' }}>{error}</div>}
        {success && <div className={styles.alert} style={{ backgroundColor: '#d4edda', color: '#155724', borderLeftColor: '#28a745' }}>{success}</div>}

        <div className={styles.tabs}>
          <button className={`${styles.tabBtn} ${activeTab === 'personal' ? styles.activeTabBtn : ''}`} onClick={() => setActiveTab('personal')}>Personal Profile</button>
          <button className={`${styles.tabBtn} ${activeTab === 'company' ? styles.activeTabBtn : ''}`} onClick={() => setActiveTab('company')}>Company Info</button>
          <button className={`${styles.tabBtn} ${activeTab === 'subusers' ? styles.activeTabBtn : ''}`} onClick={() => setActiveTab('subusers')}>Team / Sub-Users</button>
        </div>

        {activeTab === 'personal' && (
          <form onSubmit={handleSavePersonal} className={styles.form}>
            <div className={styles.section}>
              <h2 className={styles.sectionTitle}>Personal Details</h2>
              <div className={styles.inputGroup}>
                <label className={styles.label}>Full Name <span className={styles.req}>*</span></label>
                <input type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className={styles.input} required />
              </div>
              <div className={styles.inputGroup}>
                <label className={styles.label}>Email</label>
                <input type="email" value={email} className={styles.inputReadonly} disabled />
                <span className={styles.hint}>Email cannot be changed. Contact support to update.</span>
              </div>
              <div className={styles.inputGroup}>
                <label className={styles.label}>Mobile <span className={styles.req}>*</span></label>
                <input type="tel" value={mobile} onChange={(e) => setMobile(e.target.value)} className={styles.input} required />
              </div>
            </div>
            <div className={styles.actions}>
              <button type="submit" className={styles.saveBtn} disabled={saving}>{saving ? 'Saving...' : 'Save Changes'}</button>
            </div>
          </form>
        )}

        {activeTab === 'company' && (
          <form onSubmit={handleSaveCompany} className={styles.form}>
            <div className={styles.section}>
              <h2 className={styles.sectionTitle}>Company Information</h2>
              <div className={styles.row}>
                <div className={styles.inputGroup}>
                  <label className={styles.label}>Company Name <span className={styles.req}>*</span></label>
                  <input type="text" value={companyName} onChange={(e) => setCompanyName(e.target.value)} className={styles.input} required />
                </div>
                <div className={styles.inputGroup}>
                  <label className={styles.label}>Company Website</label>
                  <input type="text" value={companyWebsite} onChange={(e) => setCompanyWebsite(e.target.value)} className={styles.input} />
                </div>
              </div>
              <div className={styles.inputGroup}>
                <label className={styles.label}>Company Address <span className={styles.req}>*</span></label>
                <input type="text" value={companyAddress} onChange={(e) => setCompanyAddress(e.target.value)} className={styles.input} required />
              </div>
              <div className={styles.row}>
                <div className={styles.inputGroup}>
                  <label className={styles.label}>Company Phone</label>
