"use client";

import React, { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import adminStyles from "../../admin.module.css";
import styles from "../../products/products.module.css";

interface Attribute {
  id: number;
  name: string;
  slug: string;
  type?: string;
}

interface Term {
  id: number;
  name: string;
  slug: string;
  sort_order: number;
  color_hex?: string;
  image_url?: string;
}

export default function AdminAttributeTermsPage() {
  const params = useParams();
  const attributeId = parseInt(params.id as string);

  const [attribute, setAttribute] = useState<Attribute | null>(null);
  const [terms, setTerms] = useState<Term[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  const [newTermName, setNewTermName] = useState("");
  const [newTermSlug, setNewTermSlug] = useState("");
  const [newTermColor, setNewTermColor] = useState("");
  const [newTermOrder, setNewTermOrder] = useState<number>(0);
  const [newTermImage, setNewTermImage] = useState("");

  const [editingTermId, setEditingTermId] = useState<number | null>(null);
  const [editTermData, setEditTermData] = useState<Partial<Term>>({});

  const [mergingTermId, setMergingTermId] = useState<number | null>(null);
  const [mergeTargetId, setMergeTargetId] = useState<number | null>(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      try {
        const [attrRes, termsRes] = await Promise.all([
          fetch(`/api/admin/attributes/${attributeId}`, { credentials: "include" }),
          fetch(`/api/admin/attributes/${attributeId}/terms`, { credentials: "include" })
        ]);

        const attrData = await attrRes.json();
        const termsData = await termsRes.json();

        if (!cancelled) {
          setAttribute(attrData.attribute || null);
          setTerms(termsData.terms || []);
        }
      } catch (err) {
        if (!cancelled) console.error("Failed to fetch attribute data", err);
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, [attributeId, refreshKey]);

  const generateSlug = (name: string) => {
    return name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '');
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setNewTermName(val);
    setNewTermSlug(generateSlug(val));
  };

  const handleAddTerm = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTermName || !newTermSlug) return;

    setSaving(true);
    try {
      const res = await fetch(`/api/admin/attributes/${attributeId}/terms`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ 
          name: newTermName, 
          slug: newTermSlug, 
          color_hex: newTermColor || null,
          image_url: newTermImage || null,
          sort_order: newTermOrder 
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      setNewTermName("");
      setNewTermSlug("");
      setNewTermColor("");
      setNewTermOrder(0);
      setNewTermImage("");
      setRefreshKey(r => r + 1);
    } catch (err) {
      alert(`Error creating term: ${err instanceof Error ? err.message : String(err)}`);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (termId: number) => {
    if (!window.confirm("Are you sure you want to delete this term?")) return;
    try {
      const res = await fetch(`/api/admin/attribute-terms/${termId}`, {
        method: 'DELETE',
        credentials: "include"
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      alert("Term deleted");
      setRefreshKey(r => r + 1);
    } catch (err) {
      alert(`Error deleting: ${err instanceof Error ? err.message : String(err)}`);
    }
  };

  const handleMerge = async (sourceId: number) => {
    if (!mergeTargetId || mergeTargetId === sourceId) return;
    if (!window.confirm("Are you sure you want to merge? The source term will be deleted and all its products/variations will be moved to the target term.")) return;

    try {
      const res = await fetch(`/api/admin/attribute-terms/${sourceId}/merge`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ target_term_id: mergeTargetId })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      setMergingTermId(null);
      setMergeTargetId(null);
      setRefreshKey(r => r + 1);
    } catch (err) {
      alert(`Error merging: ${err instanceof Error ? err.message : String(err)}`);
    }
  };

  const startEditing = (term: Term) => {
    setEditingTermId(term.id);
    setEditTermData(term);
  };

  const handleUpdateTerm = async (id: number) => {
    try {
      const res = await fetch(`/api/admin/attribute-terms/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify(editTermData)
      });

      if (!res.ok) throw new Error("Failed to update term");

      setEditingTermId(null);
      setRefreshKey(r => r + 1);
    } catch (err) {
      alert(err instanceof Error ? err.message : String(err));
    }
  };

  return (
    <div className={adminStyles.adminPage}>
      <Link href="/crown-admin/attributes" className={styles.backLink}>
        &larr; Back to Attributes
      </Link>

      <div className={adminStyles.adminHeader}>
        <h1>{attribute ? `Product ${attribute.name}` : "Attribute Terms"}</h1>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '2rem', alignItems: 'start' }}>

        {/* Add New Term Sidebar */}
        <div className={styles.card}>
          <h3 className={styles.cardTitle}>Add New {attribute ? attribute.name : "Term"}</h3>
          <p style={{ fontSize: '0.85rem', color: '#64748b', marginBottom: '1rem' }}>
            Add new terms for this attribute (e.g. if the attribute is &quot;Size&quot;, add &quot;Small&quot;, &quot;Medium&quot;, etc).
          </p>
          <form onSubmit={handleAddTerm}>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Name</label>
              <input 
                required
                type="text" 
                className={styles.fieldInput} 
                value={newTermName}
                onChange={handleNameChange}
                placeholder="e.g. Small"
              />
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Slug</label>
              <input 
                required
                type="text" 
                className={styles.fieldInput} 
                value={newTermSlug}
                onChange={e => setNewTermSlug(e.target.value)}
                placeholder="e.g. small"
              />
            </div>
            {attribute?.type === 'color' && (
              <div className={styles.fieldGroup}>
                <label className={styles.fieldLabel}>Color Hex</label>
                <input 
                  type="color" 
                  className={styles.fieldInput} 
                  value={newTermColor || "#000000"}
                  onChange={e => setNewTermColor(e.target.value)}
                  style={{ height: '40px', padding: '0.2rem' }}
                />
              </div>
            )}
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Sort Order</label>
              <input 
                type="number" 
                className={styles.fieldInput} 
                value={newTermOrder}
                onChange={e => setNewTermOrder(parseInt(e.target.value) || 0)}
              />
            </div>
            {attribute?.type === 'button' && (
              <div className={styles.fieldGroup}>
                <label className={styles.fieldLabel}>Image URL (optional)</label>
                <input 
                  type="text" 
                  className={styles.fieldInput} 
                  value={newTermImage}
                  onChange={e => setNewTermImage(e.target.value)}
                  placeholder="https://..."
                />
              </div>
            )}
            <button type="submit" className={adminStyles.primaryBtn} disabled={saving} style={{ width: '100%', marginTop: '0.5rem' }}>
              {saving ? "Adding..." : "Add New Term"}
            </button>
          </form>
        </div>

        {/* Terms List */}
        <div className={styles.card}>
          {loading ? (
            <div style={{ padding: '2rem', textAlign: 'center', color: '#666' }}>Loading terms...</div>
          ) : (
            <table className={styles.table} style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '2px solid #e2e8f0', textAlign: 'left' }}>
                  <th style={{ padding: '1rem' }}>Name</th>
                  <th style={{ padding: '1rem' }}>Slug</th>
                  <th style={{ padding: '1rem' }}>Order</th>
                  {attribute?.type === 'color' && <th style={{ padding: '1rem' }}>Color</th>}
                  {attribute?.type === 'button' && <th style={{ padding: '1rem' }}>Image</th>}
                  <th style={{ padding: '1rem', textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {terms.length === 0 ? (
                  <tr>
                    <td colSpan={3} style={{ padding: '2rem', textAlign: 'center', color: '#666' }}>
                      No terms found. Create your first one!
                    </td>
                  </tr>
                ) : (
                  terms.map(term => (
                    <tr key={term.id} style={{ borderBottom: '1px solid #e2e8f0' }}>
                      {editingTermId === term.id ? (
                        <>
                          <td style={{ padding: '1rem' }}>
                            <input 
                              type="text" 
                              className={styles.fieldInput} 
                              value={editTermData.name || ""}
                              onChange={e => setEditTermData({...editTermData, name: e.target.value, slug: generateSlug(e.target.value)})}
                            />
                          </td>
                          <td style={{ padding: '1rem' }}>
                            <input 
                              type="text" 
                              className={styles.fieldInput} 
                              value={editTermData.slug || ""}
                              onChange={e => setEditTermData({...editTermData, slug: e.target.value})}
                            />
                          </td>
                          <td style={{ padding: '1rem' }}>
                            <input 
                              type="number" 
                              className={styles.fieldInput} 
                              style={{ width: '80px' }}
                              value={editTermData.sort_order || 0}
                              onChange={e => setEditTermData({...editTermData, sort_order: parseInt(e.target.value) || 0})}
                            />
                          </td>
                          {attribute?.type === 'color' && (
                            <td style={{ padding: '1rem' }}>
                              <input 
                                type="color" 
                                className={styles.fieldInput} 
                                value={editTermData.color_hex || "#000000"}
                                onChange={e => setEditTermData({...editTermData, color_hex: e.target.value})}
                                style={{ height: '40px', padding: '0.2rem', width: '60px' }}
                              />
                            </td>
                          )}
                          {attribute?.type === 'button' && (
                            <td style={{ padding: '1rem' }}>
                              <input 
                                type="text" 
                                className={styles.fieldInput} 
                                value={editTermData.image_url || ""}
                                onChange={e => setEditTermData({...editTermData, image_url: e.target.value})}
                                placeholder="https://..."
                              />
                            </td>
                          )}
                          <td style={{ padding: '1rem', textAlign: 'right' }}>
                            <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                              <button 
                                onClick={() => handleUpdateTerm(term.id)}
                                className={adminStyles.primaryBtn}
                                style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                              >
                                Save
                              </button>
                              <button 
                                onClick={() => setEditingTermId(null)}
                                className={styles.btnSecondary}
                                style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                              >
                                Cancel
                              </button>
                            </div>
                          </td>
                        </>
                      ) : (
                        <>
                          <td style={{ padding: '1rem' }}>
                            <strong>{term.name}</strong>
                          </td>
                          <td style={{ padding: '1rem', color: '#666' }}>{term.slug}</td>
                          <td style={{ padding: '1rem' }}>{term.sort_order}</td>
                          {attribute?.type === 'color' && (
                            <td style={{ padding: '1rem' }}>
                              <div style={{ width: '24px', height: '24px', borderRadius: '50%', backgroundColor: term.color_hex || '#ccc', border: '1px solid #ddd' }} title={term.color_hex}></div>
                            </td>
                          )}
                          {attribute?.type === 'button' && (
                            <td style={{ padding: '1rem' }}>
                              {term.image_url ? (
                                <img src={term.image_url} alt={term.name} style={{ width: '24px', height: '24px', objectFit: 'contain' }} />
                              ) : (
                                <span style={{ color: '#999', fontSize: '0.85rem' }}>None</span>
                              )}
                            </td>
                          )}
                          <td style={{ padding: '1rem', textAlign: 'right' }}>
                            {mergingTermId === term.id ? (
                              <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end', alignItems: 'center' }}>
                                <select 
                                  className={styles.fieldSelect} 
                                  style={{ padding: '0.2rem', width: '120px' }}
                                  value={mergeTargetId || ""}
                                  onChange={e => setMergeTargetId(parseInt(e.target.value))}
                                >
                                  <option value="">Merge into...</option>
                                  {terms.filter(t => t.id !== term.id).map(t => (
                                    <option key={t.id} value={t.id}>{t.name}</option>
                                  ))}
                                </select>
                                <button 
                                  onClick={() => handleMerge(term.id)}
                                  className={adminStyles.primaryBtn}
                                  style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                                  disabled={!mergeTargetId}
                                >
                                  Confirm
                                </button>
                                <button 
                                  onClick={() => { setMergingTermId(null); setMergeTargetId(null); }}
                                  className={styles.btnSecondary}
                                  style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                                >
                                  Cancel
                                </button>
                              </div>
                            ) : (
                              <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                                <button 
                                  onClick={() => startEditing(term)}
                                  className={styles.btnSecondary}
                                  style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                                >
                                  Edit
                                </button>
                                <button 
                                  onClick={() => setMergingTermId(term.id)}
                                  className={styles.btnSecondary}
                                  style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                                >
                                  Merge
                                </button>
                                <button 
                                  onClick={() => handleDelete(term.id)}
                                  className={styles.btnCancel}
                                  style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem', color: '#dc2626', borderColor: '#fee2e2', background: '#fee2e2' }}
                                >
                                  Delete
                                </button>
                              </div>
                            )}
                          </td>
                        </>
                      )}
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import { useRouter } from "next/navigation";
import styles from "./banners.module.css";
import adminStyles from "../admin.module.css";
import {
  FiAlignLeft, FiAlignCenter, FiAlignRight,
  FiUpload, FiTrash2, FiRefreshCw, FiEye
} from "react-icons/fi";
import MediaPicker from "../../../components/media/MediaPicker";

interface BannerData {
  id?: string;
  title: string;
  heading1: string;
  heading2: string;
  paragraph: string;
  cta_text: string;
  cta_link: string;
  bg_image_desktop: string;
  bg_image_desktop_media_id?: string;
  bg_image_mobile: string;
  bg_image_mobile_media_id?: string;
  overlay_color: string;
  overlay_opacity: number;
  text_color: string;
  text_align: string;
  banner_height: string;
  padding_x: number;
  padding_y: number;
  is_active: boolean;
}

const defaultBanner: BannerData = {
  title: "",
  heading1: "",
  heading2: "",
  paragraph: "",
  cta_text: "",
  cta_link: "",
  bg_image_desktop: "",
  bg_image_desktop_media_id: "",
  bg_image_mobile: "",
  bg_image_mobile_media_id: "",
  overlay_color: "#000000",
  overlay_opacity: 40,
  text_color: "#FFFFFF",
  text_align: "center",
  banner_height: "large",
  padding_x: 40,
  padding_y: 60,
  is_active: false,
};

const heightMap: Record<string, string> = {
  small: "300px",
  medium: "450px",
  large: "600px",
  fullscreen: "100vh",
};

export default function BannerEditor({
  initialData,
  isEdit = false,
}: {
  initialData?: any;
  isEdit?: boolean;
}) {
  const router = useRouter();
  const desktopInputRef = useRef<HTMLInputElement>(null);
  const mobileInputRef = useRef<HTMLInputElement>(null);

  const [form, setForm] = useState<BannerData>({
    ...defaultBanner,
    ...initialData,
    overlay_opacity: initialData?.overlay_opacity ?? 40,
    padding_x: initialData?.padding_x ?? 40,
    padding_y: initialData?.padding_y ?? 60,
    is_active: initialData?.is_active ?? false,
  });

  const [desktopFile, setDesktopFile] = useState<File | null>(null);
  const [mobileFile, setMobileFile] = useState<File | null>(null);
  const [desktopPreview, setDesktopPreview] = useState<string>(
    initialData?.bg_image_desktop || ""
  );
  const [mobilePreview, setMobilePreview] = useState<string>(
    initialData?.bg_image_mobile || ""
  );
  const [isDesktopPickerOpen, setIsDesktopPickerOpen] = useState(false);
  const [isMobilePickerOpen, setIsMobilePickerOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  const updateField = useCallback(
    (field: keyof BannerData, value: any) => {
      setForm((prev) => ({ ...prev, [field]: value }));
    },
    []
  );

  // ── Collection link integration ──────────────────────
  interface CollectionItem {
    id: string;
    name: string;
    slug: string;
  }

  const [collections, setCollections] = useState<CollectionItem[]>([]);
  const [linkType, setLinkType] = useState<"collection" | "custom">(
    initialData?.cta_link?.startsWith("/collections/") ? "collection" : "custom"
  );

  useEffect(() => {
    const fetchCollections = async () => {
      try {
        const res = await fetch(
          `/api/admin/collections`,
          { credentials: "include" }
        );
        if (res.ok) {
          const data = await res.json();
          setCollections(data.collections || []);
        }
      } catch (err) {
        console.error("Failed to fetch collections:", err);
      }
    };
    fetchCollections();
  }, []);

  const handleDesktopFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setDesktopFile(file);
      setDesktopPreview(URL.createObjectURL(file));
    }
  };

  const handleMobileFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setMobileFile(file);
      setMobilePreview(URL.createObjectURL(file));
    }
  };

  const removeDesktopImage = () => {
    setDesktopFile(null);
    setDesktopPreview("");
    updateField("bg_image_desktop", "");
    updateField("bg_image_desktop_media_id", "");
    if (desktopInputRef.current) desktopInputRef.current.value = "";
  };

  const removeMobileImage = () => {
    setMobileFile(null);
    setMobilePreview("");
    updateField("bg_image_mobile", "");
    updateField("bg_image_mobile_media_id", "");
    if (mobileInputRef.current) mobileInputRef.current.value = "";
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);

    try {
      const data = new FormData();
      data.append("title", form.title);
      data.append("heading1", form.heading1);
      data.append("heading2", form.heading2);
      data.append("paragraph", form.paragraph);
      data.append("cta_text", form.cta_text);
      data.append("cta_link", form.cta_link);
      data.append("overlay_color", form.overlay_color);
      data.append("overlay_opacity", String(form.overlay_opacity));
      data.append("text_color", form.text_color);
      data.append("text_align", form.text_align);
      data.append("banner_height", form.banner_height);
      data.append("padding_x", String(form.padding_x));
      data.append("padding_y", String(form.padding_y));
      data.append("is_active", String(form.is_active));

      if (desktopFile) {
        data.append("bg_image_desktop", desktopFile);
      } else if (form.bg_image_desktop) {
        data.append("existing_bg_desktop", form.bg_image_desktop);
      }
      if (form.bg_image_desktop_media_id) {
        data.append("bg_image_desktop_media_id", form.bg_image_desktop_media_id);
      }

      if (mobileFile) {
        data.append("bg_image_mobile", mobileFile);
      } else if (form.bg_image_mobile) {
        data.append("existing_bg_mobile", form.bg_image_mobile);
      }
      if (form.bg_image_mobile_media_id) {
        data.append("bg_image_mobile_media_id", form.bg_image_mobile_media_id);
      }

      const url = isEdit
        ? `/api/admin/banners/${initialData.id}`
        : `/api/admin/banners`;

      const method = isEdit ? "PUT" : "POST";

      const res = await fetch(url, {
        method: method,
        body: data,
        credentials: "include",
      });

      const result = await res.json();

      if (res.ok) {
        router.push("/crown-admin/banners");
      } else {
        setError(result.error || "Failed to save banner");
      }
    } catch {
      setError("An error occurred while saving.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Preview height computation
  const previewHeight = heightMap[form.banner_height] || "600px";

  return (
    <>
      <div className={adminStyles.pageHeader}>
        <h1 className={adminStyles.pageTitle}>
          {isEdit ? "Edit Banner" : "Create New Banner"}
        </h1>
      </div>

      {error && <div className={adminStyles.errorMessage}>{error}</div>}
      {successMsg && (
        <div style={{ background: "#d4edda", color: "#155724", padding: "1rem", marginBottom: "1.5rem", borderLeft: "4px solid #28a745" }}>
          {successMsg}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className={styles.editorLayout}>
          {/* ─── Left Panel: Content ─────────────────── */}
          <div className={styles.editorPanel}>
            <h3>Banner Content</h3>

            <div className={styles.field}>
              <label>Internal Title *</label>
              <input
                type="text"
                value={form.title}
                onChange={(e) => updateField("title", e.target.value)}
                placeholder="e.g. Summer Sale 2026"
                required
              />
              <div className={styles.fieldHint}>For admin reference only — not displayed on the website</div>
            </div>

            <div className={styles.fieldRow}>
              <div className={styles.field}>
                <label>Heading 1 (Primary)</label>
                <input
                  type="text"
                  value={form.heading1}
                  onChange={(e) => updateField("heading1", e.target.value)}
                  placeholder="e.g. SUMMER COLLECTION"
                />
              </div>
              <div className={styles.field}>
                <label>Heading 2 (Secondary)</label>
                <input
                  type="text"
                  value={form.heading2}
                  onChange={(e) => updateField("heading2", e.target.value)}
                  placeholder="e.g. Up to 30% Off"
                />
              </div>
            </div>

            <div className={styles.field}>
              <label>Paragraph Text</label>
              <textarea
                value={form.paragraph}
                onChange={(e) => updateField("paragraph", e.target.value)}
                placeholder="Promotional message or description..."
                rows={3}
              />
            </div>

            <div className={styles.fieldRow}>
              <div className={styles.field}>
                <label>CTA Button Text</label>
                <input
                  type="text"
                  value={form.cta_text}
                  onChange={(e) => updateField("cta_text", e.target.value)}
                  placeholder="e.g. Shop Now"
                />
              </div>
              <div className={styles.field}>
                <label>CTA Button Link</label>
                <div className={styles.linkTypeToggle}>
                  <button
                    type="button"
                    className={`${styles.linkTypeBtn} ${linkType === "collection" ? styles.active : ""}`}
                    onClick={() => {
                      setLinkType("collection");
                      updateField("cta_link", "");
                    }}
                  >
                    Collection
                  </button>
                  <button
                    type="button"
                    className={`${styles.linkTypeBtn} ${linkType === "custom" ? styles.active : ""}`}
                    onClick={() => {
                      setLinkType("custom");
                      updateField("cta_link", "");
                    }}
                  >
                    Custom Link
                  </button>
                </div>
                {linkType === "collection" ? (
                  <>
                    <select
                      value={form.cta_link}
                      onChange={(e) => updateField("cta_link", e.target.value)}
                    >
                      <option value="">— Select a collection —</option>
                      {collections.map((col) => (
                        <option key={col.id} value={`/collections/${col.slug}`}>
                          {col.name}
                        </option>
                      ))}
                    </select>
                    {form.cta_link && (
                      <div className={styles.fieldHint}>
                        Link: {form.cta_link}
                      </div>
                    )}
                  </>
                ) : (
                  <input
                    type="text"
                    value={form.cta_link}
                    onChange={(e) => updateField("cta_link", e.target.value)}
                    placeholder="e.g. /products or https://..."
                  />
                )}
              </div>
            </div>

            {/* Desktop Image Upload */}
            <div className={styles.field}>
              <label>Desktop Background Image</label>
              <input
                ref={desktopInputRef}
                type="file"
                accept="image/jpeg,image/png,image/webp"
                onChange={handleDesktopFile}
                style={{ display: "none" }}
              />
              {desktopPreview ? (
                <>
                  <div
                    className={`${styles.imageUploadZone} ${styles.hasImage}`}
                  >
                    <img
                      src={desktopPreview}
                      alt="Desktop preview"
                      className={styles.imagePreview}
                    />
                  </div>
                  <div className={styles.imageActions}>
                    <button
                      type="button"
                      className={styles.imageActionBtn}
                      onClick={() => desktopInputRef.current?.click()}
                    >
                      <FiRefreshCw style={{ marginRight: 4 }} /> Replace File
                    </button>
                    <button
                      type="button"
                      className={styles.imageActionBtn}
                      onClick={() => setIsDesktopPickerOpen(true)}
                    >
                      Choose from Library
                    </button>
                    <button
                      type="button"
                      className={`${styles.imageActionBtn} ${styles.imageActionBtnDanger}`}
                      onClick={removeDesktopImage}
                    >
                      <FiTrash2 style={{ marginRight: 4 }} /> Remove
                    </button>
                  </div>
                </>
              ) : (
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'stretch' }}>
                  <div
                    className={styles.imageUploadZone}
                    onClick={() => desktopInputRef.current?.click()}
                    style={{ flex: 1 }}
                  >
                    <div className={styles.imageUploadIcon}>
                      <FiUpload />
                    </div>
                    <div className={styles.imageUploadText}>
                      <strong>Click to upload</strong> desktop background image
                    </div>
                  </div>
                  <button
                    type="button"
                    onClick={() => setIsDesktopPickerOpen(true)}
                    style={{
                      padding: '0 1.25rem',
                      background: '#1a1a2e',
                      color: '#d4af37',
                      border: '1px solid #d4af37',
                      borderRadius: '8px',
                      cursor: 'pointer',
                      fontWeight: 600
                    }}
                  >
                    Choose from Library
                  </button>
                </div>
              )}
            </div>

            {/* Mobile Image Upload */}
            <div className={styles.field}>
              <label>Mobile Background Image (Optional)</label>
              <input
                ref={mobileInputRef}
                type="file"
                accept="image/jpeg,image/png,image/webp"
                onChange={handleMobileFile}
                style={{ display: "none" }}
              />
              {mobilePreview ? (
                <>
                  <div
                    className={`${styles.imageUploadZone} ${styles.hasImage}`}
                  >
                    <img
                      src={mobilePreview}
                      alt="Mobile preview"
                      className={styles.imagePreview}
                    />
                  </div>
                  <div className={styles.imageActions}>
                    <button
                      type="button"
                      className={styles.imageActionBtn}
                      onClick={() => mobileInputRef.current?.click()}
                    >
                      <FiRefreshCw style={{ marginRight: 4 }} /> Replace File
                    </button>
                    <button
                      type="button"
                      className={styles.imageActionBtn}
                      onClick={() => setIsMobilePickerOpen(true)}
                    >
                      Choose from Library
                    </button>
                    <button
                      type="button"
                      className={`${styles.imageActionBtn} ${styles.imageActionBtnDanger}`}
                      onClick={removeMobileImage}
                    >
                      <FiTrash2 style={{ marginRight: 4 }} /> Remove
                    </button>
                  </div>
                </>
              ) : (
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'stretch' }}>
                  <div
                    className={styles.imageUploadZone}
                    onClick={() => mobileInputRef.current?.click()}
                    style={{ flex: 1 }}
                  >
                    <div className={styles.imageUploadIcon}>
                      <FiUpload />
                    </div>
                    <div className={styles.imageUploadText}>
                      <strong>Click to upload</strong> mobile-optimized image
                    </div>
                  </div>
                  <button
                    type="button"
                    onClick={() => setIsMobilePickerOpen(true)}
                    style={{
                      padding: '0 1.25rem',
                      background: '#1a1a2e',
                      color: '#d4af37',
                      border: '1px solid #d4af37',
                      borderRadius: '8px',
                      cursor: 'pointer',
                      fontWeight: 600
                    }}
                  >
                    Choose from Library
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* ─── Right Panel: Styling Controls ────────── */}
          <div className={styles.controlsPanel}>
            <h3>Styling Controls</h3>

            {/* Active Toggle */}
            <div className={styles.statusToggle}>
              <div
                className={`${styles.toggleSwitch} ${form.is_active ? styles.active : ""}`}
                onClick={() => updateField("is_active", !form.is_active)}
              />
              <div>
                <div className={styles.toggleLabel}>
                  {form.is_active ? "Active" : "Inactive"}
                </div>
                <div className={styles.toggleHint}>
                  {form.is_active
                    ? "Banner is visible on the homepage"
                    : "Banner is hidden from homepage"}
                </div>
              </div>
            </div>

            {/* Text Alignment */}
            <div className={styles.field}>
              <label>Text Alignment</label>
              <div className={styles.alignmentGroup}>
