"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import adminStyles from "../admin.module.css";
import styles from "./banners.module.css";

interface Banner {
  id: string;
  title: string;
  heading1: string;
  bg_image_desktop: string;
  is_active: boolean;
  banner_height: string;
  created_at: string;
}

export default function AdminBannersList() {
  const [banners, setBanners] = useState<Banner[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");
  const [togglingId, setTogglingId] = useState<string | null>(null);

  const fetchBanners = async (status = "all") => {
    setLoading(true);
    try {
      const res = await fetch(
        `/api/admin/banners?status=${status}`,
        { credentials: "include" }
      );
      const data = await res.json();
      setBanners(data.banners || []);
    } catch (err) {
      console.error("Failed to fetch banners", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBanners(filter);
  }, [filter]);

  const handleDelete = async (id: string) => {
    if (!window.confirm("Are you sure you want to delete this banner?")) return;
    try {
      const res = await fetch(
        `/api/admin/banners/${id}`,
        { method: "DELETE", credentials: "include" }
      );
      if (res.ok) {
        setBanners(banners.filter((b) => b.id !== id));
      } else {
        alert("Failed to delete banner.");
      }
    } catch {
      alert("Error deleting banner.");
    }
  };

  const handleToggle = async (id: string) => {
    setTogglingId(id);
    try {
      const res = await fetch(
        `/api/admin/banners/${id}/toggle`,
        { method: "PATCH", credentials: "include" }
      );
      if (res.ok) {
        // Refresh list to reflect deactivation of other banners
        await fetchBanners(filter);
      } else {
        alert("Failed to toggle banner.");
      }
    } catch {
      alert("Error toggling banner.");
    } finally {
      setTogglingId(null);
    }
  };

  return (
    <>
      <div className={adminStyles.pageHeader}>
        <h1 className={adminStyles.pageTitle}>Manage Banners</h1>
        <Link href="/crown-admin/banners/new" className={adminStyles.btnPrimary}>
          Create New Banner
        </Link>
      </div>

      <div style={{ marginBottom: "1.5rem", display: "flex", gap: "1rem" }}>
        <button
          onClick={() => setFilter("all")}
          className={filter === "all" ? adminStyles.btnPrimary : adminStyles.btnSecondary}
        >
          All
        </button>
        <button
          onClick={() => setFilter("active")}
          className={filter === "active" ? adminStyles.btnPrimary : adminStyles.btnSecondary}
        >
          Active
        </button>
        <button
          onClick={() => setFilter("inactive")}
          className={filter === "inactive" ? adminStyles.btnPrimary : adminStyles.btnSecondary}
        >
          Inactive
        </button>
      </div>

      <div className={adminStyles.tableContainer}>
        {loading ? (
          <div style={{ padding: "2rem", textAlign: "center" }}>Loading...</div>
        ) : (
          <table className={adminStyles.adminTable}>
            <thead>
              <tr>
                <th>Preview</th>
                <th>Title</th>
                <th>Heading</th>
                <th>Status</th>
                <th>Height</th>
                <th>Created</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {banners.length === 0 ? (
                <tr>
                  <td colSpan={7} style={{ textAlign: "center", padding: "2rem" }}>
                    No banners found. Create one to get started!
                  </td>
                </tr>
              ) : (
                banners.map((banner) => (
                  <tr key={banner.id}>
                    <td>
                      {banner.bg_image_desktop ? (
                        <img
                          src={banner.bg_image_desktop}
                          alt={banner.title}
                          className={styles.bannerThumb}
                        />
                      ) : (
                        <div className={styles.bannerThumbPlaceholder}>
                          No image
                        </div>
                      )}
                    </td>
                    <td style={{ fontWeight: 600 }}>{banner.title}</td>
                    <td style={{ color: "#666", maxWidth: 200, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      {banner.heading1 || "—"}
                    </td>
                    <td>
                      <span className={banner.is_active ? styles.badgeActive : styles.badgeInactive}>
                        {banner.is_active ? "Active" : "Inactive"}
                      </span>
                    </td>
                    <td style={{ textTransform: "capitalize" }}>
                      {banner.banner_height}
                    </td>
                    <td>
                      {new Date(banner.created_at).toLocaleDateString()}
                    </td>
                    <td>
                      <div className={adminStyles.tableActions}>
                        <Link
                          href={`/crown-admin/banners/${banner.id}/edit`}
                          className={adminStyles.tableBtn}
                        >
                          Edit
                        </Link>
                        <button
                          onClick={() => handleToggle(banner.id)}
                          disabled={togglingId === banner.id}
                          className={`${styles.toggleBtn} ${banner.is_active ? styles.toggleBtnOff : ""}`}
                        >
                          {togglingId === banner.id
                            ? "..."
                            : banner.is_active
                              ? "Deactivate"
                              : "Activate"}
                        </button>
                        <button
                          onClick={() => handleDelete(banner.id)}
                          className={`${adminStyles.tableBtn} ${adminStyles.tableBtnDanger}`}
                        >
                          Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
}

"use client";

import { useState, useRef, useMemo, useEffect } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import styles from "../admin.module.css";
import "react-quill-new/dist/quill.snow.css";
import MediaPicker from "../../../components/media/MediaPicker";

const ReactQuill = dynamic(() => import("react-quill-new"), {
  ssr: false,
  loading: () => <p>Loading editor...</p>,
});

const QuillEditor = ReactQuill as React.ComponentType<any>;

interface BlogData {
  id?: string;
  title: string;
  slug: string;
  excerpt: string;
  content: string;
  status: string;
  tags: string; // We'll keep it as a comma-separated string for the form
  category: string;
  meta_description: string;
  cover_image?: string;
  cover_image_media_id?: string;
}

export default function BlogEditor({ initialData, isEdit = false }: { initialData?: any, isEdit?: boolean }) {
  const router = useRouter();
  const quillRef = useRef<any>(null);

  const [formData, setFormData] = useState<BlogData>({
    title: initialData?.title || "",
    slug: initialData?.slug || "",
    excerpt: initialData?.excerpt || "",
    content: initialData?.content || "",
    status: initialData?.status || "draft",
    tags: initialData?.tags ? initialData.tags.join(', ') : "",
    category: initialData?.category || "",
    meta_description: initialData?.meta_description || "",
    cover_image: initialData?.cover_image || "",
    cover_image_media_id: initialData?.cover_image_media_id || "",
  });

  const [coverFile, setCoverFile] = useState<File | null>(null);
  const [coverPreview, setCoverPreview] = useState<string | null>(initialData?.cover_image || null);
  const [isPickerOpen, setIsPickerOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Category suggestions
  const [existingCategories, setExistingCategories] = useState<string[]>([]);
  const [showCategorySuggestions, setShowCategorySuggestions] = useState(false);

  useEffect(() => {
    // Fetch existing categories for suggestions
    async function fetchCategories() {
      try {
        const res = await fetch(`/api/blogs/categories`);
        if (res.ok) {
          const data = await res.json();
          setExistingCategories(data.categories || []);
        }
      } catch {
        // silent fail
      }
    }
    fetchCategories();
  }, []);

  const filteredCategories = existingCategories.filter(
    (cat) => cat.toLowerCase().includes(formData.category.toLowerCase()) && cat.toLowerCase() !== formData.category.toLowerCase()
  );

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleContentChange = (content: string) => {
    setFormData({ ...formData, content });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setCoverFile(file);
      setCoverPreview(URL.createObjectURL(file));
    }
  };

  // Custom Image Handler for Quill
  const imageHandler = () => {
    const input = document.createElement("input");
    input.setAttribute("type", "file");
    input.setAttribute("accept", "image/*");
    input.click();

    input.onchange = async () => {
      const file = input.files ? input.files[0] : null;
      if (!file) return;

      const formData = new FormData();
      formData.append("image", file);

      try {
        const res = await fetch(`/api/admin/upload-image`, {
          method: "POST",
          body: formData,
          credentials: "include"
        });

        if (res.status === 401) {
          alert("Session expired. Please log in again.");
          router.push("/crown-admin/login");
          return;
        }

        const data = await res.json();

        if (res.ok && data.url) {
          const quill = quillRef.current?.getEditor();
          if (quill) {
            const range = quill.getSelection(true);
            quill.insertEmbed(range.index, "image", data.url);
          }
        } else {
          alert(data.error || "Image upload failed");
        }
      } catch (err) {
        console.error("Upload error", err);
        alert("Image upload failed");
      }
    };
  };

  const modules = useMemo(() => ({
    toolbar: {
      container: [
        [{ 'header': [1, 2, 3, false] }],
        ['bold', 'italic', 'underline', 'strike', 'blockquote'],
        [{ 'list': 'ordered' }, { 'list': 'bullet' }],
        ['link', 'image'],
        ['clean']
      ],
      handlers: {
        image: imageHandler
      }
    }
  }), []);

  const handleMediaSelect = (selected: { url: string; mediaId: string; alt_text?: string; title?: string }[]) => {
    if (selected.length > 0) {
      setCoverFile(null);
      setCoverPreview(selected[0].url);
      setFormData(prev => ({
        ...prev,
        cover_image: selected[0].url,
        cover_image_media_id: selected[0].mediaId
      }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      const data = new FormData();
      data.append("title", formData.title);
      data.append("slug", formData.slug);
      data.append("excerpt", formData.excerpt);
      data.append("content", formData.content);
      data.append("status", formData.status);
      data.append("tags", formData.tags);
      data.append("category", formData.category);
      data.append("meta_description", formData.meta_description);

      if (coverFile) {
        data.append("cover_image", coverFile);
      } else if (formData.cover_image) {
        data.append("existing_cover", formData.cover_image);
      }

      if (formData.cover_image_media_id) {
        data.append("cover_image_media_id", formData.cover_image_media_id);
      }

      const url = isEdit
        ? `/api/admin/blogs/${initialData.id}`
        : `/api/admin/blogs`;

      const method = isEdit ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        body: data,
        credentials: "include"
      });

      const result = await res.json();

      if (res.ok) {
        router.push("/crown-admin/blogs");
      } else {
        setError(result.error || "Failed to save blog");
      }
    } catch (err) {
      setError("An error occurred while saving.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <>
      <div className={styles.pageHeader}>
        <h1 className={styles.pageTitle}>{isEdit ? "Edit Blog" : "Create New Blog"}</h1>
      </div>

      {error && <div className={styles.errorMessage}>{error}</div>}

      <form onSubmit={handleSubmit} encType="multipart/form-data">
        <div className={styles.formRow}>
          <div className={styles.formGroup}>
            <label>Title *</label>
            <input
              type="text"
              name="title"
              className={styles.formControl}
              value={formData.title}
              onChange={handleChange}
              required
            />
          </div>
          <div className={styles.formGroup}>
            <label>Slug (Leave blank to auto-generate)</label>
            <input
              type="text"
              name="slug"
              className={styles.formControl}
              value={formData.slug}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className={styles.formGroup}>
          <label>Cover Image (Required for new blogs)</label>

          {coverPreview && (
            <div style={{ marginBottom: '1rem', maxWidth: '300px', borderRadius: '6px', overflow: 'hidden', border: '1px solid #cbd5e1' }}>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img src={coverPreview} alt="Cover Preview" style={{ width: '100%', display: 'block' }} />
            </div>
          )}

          <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
            <button
              type="button"
              onClick={() => setIsPickerOpen(true)}
              style={{
                padding: '0.6rem 1.25rem',
                background: '#1a1a2e',
                color: '#d4af37',
                border: '1px solid #d4af37',
                borderRadius: '6px',
                fontWeight: 600,
                cursor: 'pointer'
              }}
            >
              Choose from Media Library
            </button>

            <span style={{ color: '#64748b', fontSize: '0.9rem' }}>or upload:</span>

            <input
              type="file"
              name="cover_image"
              accept="image/jpeg, image/png, image/webp"
              onChange={handleFileChange}
              required={!isEdit && !formData.cover_image && !coverFile}
            />
          </div>
        </div>

        <div className={styles.formGroup}>
          <label>Excerpt / Short Description</label>
          <textarea
            name="excerpt"
            className={styles.formControl}
            rows={3}
            value={formData.excerpt}
            onChange={handleChange}
          ></textarea>
        </div>

        <div className={styles.formGroup}>
          <label>Content *</label>
          <div className={styles.editorContainer}>
            <QuillEditor
              ref={quillRef}
              theme="snow"
              value={formData.content}
              onChange={handleContentChange}
              modules={modules}
            />
          </div>
        </div>

        <div className={styles.formRow}>
          <div className={styles.formGroup}>
            <label>Category</label>
            <div style={{ position: "relative" }}>
              <input
                type="text"
                name="category"
                className={styles.formControl}
                value={formData.category}
                onChange={handleChange}
                onFocus={() => setShowCategorySuggestions(true)}
                onBlur={() => setTimeout(() => setShowCategorySuggestions(false), 200)}
                placeholder="Type to search or create new..."
                autoComplete="off"
              />
              {showCategorySuggestions && (filteredCategories.length > 0 || (existingCategories.length > 0 && formData.category === "")) && (
                <div style={{
                  position: "absolute",
                  top: "100%",
                  left: 0,
                  right: 0,
                  background: "#fff",
                  border: "1px solid #dcdcdc",
                  borderTop: "none",
                  maxHeight: "180px",
                  overflowY: "auto",
                  zIndex: 20,
                  boxShadow: "0 4px 12px rgba(0,0,0,0.08)"
                }}>
                  {(formData.category === "" ? existingCategories : filteredCategories).map((cat) => (
                    <div
                      key={cat}
                      style={{
                        padding: "0.6rem 0.75rem",
                        cursor: "pointer",
                        fontSize: "0.95rem",
                        borderBottom: "1px solid #f0f0f0",
                        transition: "background 0.15s"
                      }}
                      onMouseDown={() => {
                        setFormData({ ...formData, category: cat });
                        setShowCategorySuggestions(false);
                      }}
                      onMouseEnter={(e) => (e.currentTarget.style.background = "#f8f9fa")}
                      onMouseLeave={(e) => (e.currentTarget.style.background = "#fff")}
                    >
                      {cat}
                    </div>
                  ))}
                </div>
              )}
            </div>
            <small style={{ color: "#888", marginTop: "0.25rem", display: "block" }}>
              Select an existing category or type a new one
            </small>
          </div>
          <div className={styles.formGroup}>
            <label>Tags (Comma separated)</label>
            <input
              type="text"
              name="tags"
              className={styles.formControl}
              placeholder="e.g. Rings, Fashion, Tips"
              value={formData.tags}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className={styles.formRow}>
          <div className={styles.formGroup}>
            <label>Status</label>
            <select
              name="status"
              className={styles.formControl}
              value={formData.status}
              onChange={handleChange}
            >
              <option value="draft">Draft</option>
              <option value="published">Published</option>
            </select>
          </div>
          <div className={styles.formGroup}>
            <label>SEO Meta Description</label>
            <input
              type="text"
              name="meta_description"
              className={styles.formControl}
              value={formData.meta_description}
              onChange={handleChange}
            />
          </div>
        </div>

        <div style={{ marginTop: '2rem' }}>
          <button type="submit" className={styles.btnPrimary} disabled={isSubmitting}>
            {isSubmitting ? "Saving..." : isEdit ? "Update Blog" : "Publish Blog"}
          </button>
        </div>
      </form>

      <MediaPicker 
        isOpen={isPickerOpen}
        onClose={() => setIsPickerOpen(false)}
        onSelect={handleMediaSelect}
        selectedUrls={formData.cover_image ? [formData.cover_image] : []}
      />
    </>
  );
}

