"use client";

import { useState, useEffect, useCallback, useRef, useMemo } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import styles from "../admin.module.css";
import nl from "./newsletter.module.css";
import {
  FiSend, FiUsers, FiClock, FiMail, FiCheckCircle, FiAlertCircle,
  FiChevronDown, FiChevronUp, FiEye, FiRefreshCw, FiX
} from "react-icons/fi";

const API = '/api/admin';

import "react-quill-new/dist/quill.snow.css";

const ReactQuill = dynamic(() => import("react-quill-new"), {
  ssr: false,
  loading: () => <p style={{ padding: 20 }}>Loading editor...</p>,
});

const QuillEditor = ReactQuill as React.ComponentType<any>;
interface Subscriber {
  id: string;
  email: string;
  name: string;
  company: string;
  type: "guest" | "member";
  status: string;
  date: string;
}

interface Campaign {
  id: string;
  subject: string;
  content: string;
  recipient_count: number;
  sent_at: string;
}

type Tab = "compose" | "subscribers" | "campaigns";

export default function NewsletterPage() {
  const router = useRouter();
  const quillRef = useRef<any>(null);
  const subjectRef = useRef<HTMLInputElement>(null);
  const testEmailRef = useRef<HTMLInputElement>(null);
  const [tab, setTab] = useState<Tab>("compose");

  // Compose state
  const [subject, setSubject] = useState("");
  const [content, setContent] = useState("");
  const [testEmail, setTestEmail] = useState("");
  const [sending, setSending] = useState(false);
  const [testSending, setTestSending] = useState(false);
  const [toast, setToast] = useState<{ type: "success" | "error"; msg: string } | null>(null);
  const [errorField, setErrorField] = useState("");

  // Subscribers state
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [subsLoading, setSubsLoading] = useState(false);

  // Campaigns state
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [campaignsLoading, setCampaignsLoading] = useState(false);
  const [expandedCampaign, setExpandedCampaign] = useState<string | null>(null);

  // Preview modal
  const [showPreview, setShowPreview] = useState(false);

  const showToast = (type: "success" | "error", msg: string) => {
    setToast({ type, msg });
    setTimeout(() => setToast(null), 5000);
  };

  // ─── Fetch subscribers ─────────────────────────────
  const fetchSubscribers = useCallback(async () => {
    setSubsLoading(true);
    try {
      const res = await fetch(`${API}/newsletter/subscribers`, { credentials: "include" });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setSubscribers(data.subscribers || []);
    } catch (err: any) {
      showToast("error", err.message || "Failed to load subscribers");
    } finally {
      setSubsLoading(false);
    }
  }, []);

  // ─── Fetch campaigns ──────────────────────────────
  const fetchCampaigns = useCallback(async () => {
    setCampaignsLoading(true);
    try {
      const res = await fetch(`${API}/newsletter/campaigns`, { credentials: "include" });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setCampaigns(data.campaigns || []);
    } catch (err: any) {
      showToast("error", err.message || "Failed to load campaigns");
    } finally {
      setCampaignsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (tab === "subscribers") fetchSubscribers();
    if (tab === "campaigns") fetchCampaigns();
  }, [tab, fetchSubscribers, fetchCampaigns]);

  // ─── Custom Image Handler ─────────────────────────────
  const imageHandler = useCallback(() => {
    const input = document.createElement("input");
    input.setAttribute("type", "file");
    input.setAttribute("accept", "image/*");
    input.click();

    input.onchange = async () => {
      const file = input.files ? input.files[0] : null;
      if (!file) return;

      const formData = new FormData();
      formData.append("image", file);

      try {
        const res = await fetch(`${API}/upload-image`, {
          method: "POST",
          body: formData,
          credentials: "include"
        });

        if (res.status === 401) {
          alert("Session expired. Please log in again.");
          router.push("/crown-admin/login");
          return;
        }

        const data = await res.json();

        if (res.ok && data.url) {
          const quill = quillRef.current?.getEditor();
          if (quill) {
            const range = quill.getSelection(true);
            quill.insertEmbed(range.index, "image", data.url);
          }
        } else {
          alert(data.error || "Image upload failed");
        }
      } catch (err) {
        console.error("Upload error", err);
        alert("Image upload failed");
      }
    };
  }, [router]);

  const modules = useMemo(() => ({
    toolbar: {
      container: [
        [{ 'header': [1, 2, 3, false] }],
        ['bold', 'italic', 'underline', 'strike', 'blockquote'],
        [{ 'list': 'ordered' }, { 'list': 'bullet' }],
        ['link', 'image'],
        ['clean']
      ],
      handlers: {
        image: imageHandler
      }
    }
  }), [imageHandler]);

  // ─── Send test email ──────────────────────────────
  const handleTestSend = async () => {
    if (!subject.trim()) {
      showToast("error", "Subject line is required.");
      setErrorField("subject");
      if (subjectRef.current) {
        subjectRef.current.focus();
      }
      return;
    }
    if (!content || content === "<p><br></p>") {
      showToast("error", "Email content is required.");
      quillRef.current?.focus();
      return;
    }
    if (!testEmail.trim()) {
      showToast("error", "Test email address is required.");
      setErrorField("testEmail");
      testEmailRef.current?.focus();
      return;
    }
    setTestSending(true);
    try {
      const res = await fetch(`${API}/newsletter/test`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ subject, content, testEmail })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      showToast("success", data.message || "Test sent!");
    } catch (err: any) {
      showToast("error", err.message);
    } finally {
      setTestSending(false);
    }
  };

  // ─── Broadcast to all ─────────────────────────────
  const handleBroadcast = async () => {
    if (!subject.trim()) {
      showToast("error", "Subject line is required.");
      setErrorField("subject");
      if (subjectRef.current) {
        subjectRef.current.focus();
      }
      return;
    }
    if (!content || content === "<p><br></p>") {
      showToast("error", "Email content is required.");
      quillRef.current?.focus();
      return;
    }
    if (!window.confirm("This will send the newsletter to ALL active subscribers. Continue?")) return;
    setSending(true);
    try {
      const res = await fetch(`${API}/newsletter/send`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ subject, content })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      showToast("success", data.message || "Newsletter sent!");
      setSubject("");
      setContent("");
    } catch (err: any) {
      showToast("error", err.message);
    } finally {
      setSending(false);
    }
  };

  // ─── Build preview HTML ─────────────────────────────
  const previewHtml = `
    <div style="font-family:'Segoe UI',Arial,sans-serif;max-width:600px;margin:0 auto;background:#fff;border:1px solid #ddd;">
      <div style="background:#1a1a2e;padding:28px 24px;text-align:center;border-bottom:3px solid #d4af37;">
        <h1 style="color:#d4af37;margin:0;font-size:26px;letter-spacing:2px;font-weight:700;">CROWN FINDINGS</h1>
        <p style="color:#a0a0b8;margin:6px 0 0;font-size:11px;letter-spacing:3px;text-transform:uppercase;">Wholesale Jewelry Findings</p>
      </div>
      <div style="padding:28px 24px;color:#333;line-height:1.7;font-size:15px;">
        ${content || '<em style="color:#999;">Your content will appear here...</em>'}
      </div>
      <div style="background:#f8f9fa;padding:20px 24px;text-align:center;border-top:1px solid #eee;font-size:11px;color:#888;">
        <p style="margin:0 0 8px;">You received this because you subscribed to Crown Findings updates.</p>
        <p style="margin:0;">Members can manage preferences in their Profile. Guests can unsubscribe anytime.</p>
        <p style="margin:10px 0 0;color:#aaa;">&copy; 2026 Crown Findings Co., Inc.</p>
      </div>
    </div>
  `;

  return (
    <>
      {/* Toast notification */}
      {toast && (
        <div className={`${nl.toast} ${toast.type === "success" ? nl.toastSuccess : nl.toastError}`}>
          {toast.type === "success" ? <FiCheckCircle /> : <FiAlertCircle />}
          <span>{toast.msg}</span>
        </div>
      )}

      {/* Page header */}
      <div className={styles.pageHeader}>
        <h1 className={styles.pageTitle}>Newsletter & Broadcasts</h1>
      </div>

      {/* Tabs */}
      <div className={nl.tabs}>
        <button
          className={`${nl.tab} ${tab === "compose" ? nl.tabActive : ""}`}
          onClick={() => setTab("compose")}
        >
          <FiMail /> Compose
        </button>
        <button
          className={`${nl.tab} ${tab === "subscribers" ? nl.tabActive : ""}`}
          onClick={() => setTab("subscribers")}
        >
          <FiUsers /> Subscribers
        </button>
        <button
          className={`${nl.tab} ${tab === "campaigns" ? nl.tabActive : ""}`}
          onClick={() => setTab("campaigns")}
        >
          <FiClock /> Campaign History
        </button>
      </div>

      {/* ═══════════════ COMPOSE TAB ═══════════════ */}
      {tab === "compose" && (
        <div className={nl.composeGrid}>
          {/* Left: Editor */}
          <div className={nl.editorPane}>
            <div className={nl.card}>
              <h3 className={nl.cardTitle}>
                <FiSend style={{ verticalAlign: "middle", marginRight: 8 }} />
                Compose Newsletter
              </h3>

              <div className={styles.formGroup}>
                <label>Subject Line</label>
                <input
                  ref={subjectRef}
                  type="text"
                  className={`${styles.formControl} ${errorField === 'subject' ? nl.errorBlink : ''}`}
                  placeholder="e.g. New Spring Collection — Now Available"
                  value={subject}
                  onChange={(e) => setSubject(e.target.value)}
                  onAnimationEnd={() => setErrorField('')}
                  required
                />
              </div>

              <div className={styles.formGroup}>
                <label>Email Content</label>
                <div style={{ background: '#fff', borderRadius: '4px', overflow: 'hidden', border: '1px solid #333' }}>
                  <QuillEditor
                    ref={quillRef}
                    theme="snow"
                    value={content}
                    onChange={setContent}
                    modules={modules}
                    style={{ minHeight: '350px' }}
                  />
                </div>
              </div>


              {/* Action buttons */}
              <div className={nl.actions}>
                <button
                  className={nl.previewBtn}
                  onClick={() => setShowPreview(true)}
                  disabled={!content}
                >
                  <FiEye /> Preview
                </button>
                <button
                  className={styles.btnPrimary}
                  onClick={handleBroadcast}
                  disabled={sending}
                >
                  <FiSend style={{ marginRight: 6 }} />
                  {sending ? "Sending…" : "Send to All Subscribers"}
                </button>
              </div>
            </div>
          </div>

          {/* Right: Test & Info */}
          <div className={nl.sidePane}>
            {/* Test send */}
            <div className={nl.card}>
              <h3 className={nl.cardTitle}>Send Test Email</h3>
              <p className={nl.cardSubtitle}>
                Send a preview to yourself before broadcasting to all subscribers.
              </p>
              <div className={styles.formGroup}>
                <input
                  ref={testEmailRef}
                  type="email"
                  className={`${styles.formControl} ${errorField === 'testEmail' ? nl.errorBlink : ''}`}
                  placeholder="your@email.com"
                  value={testEmail}
                  onChange={(e) => setTestEmail(e.target.value)}
                  onAnimationEnd={() => setErrorField('')}
                />
              </div>
              <button
                className={styles.btnSecondary}
                onClick={handleTestSend}
                disabled={testSending}
                style={{ width: "100%" }}
              >
                {testSending ? "Sending…" : "Send Test"}
              </button>
            </div>

            {/* Tips */}
            <div className={nl.card}>
              <h3 className={nl.cardTitle}>Tips</h3>
              <ul className={nl.tipsList}>
                <li>Use the toolbar to easily format text, add lists, or insert links</li>
                <li>Upload custom images directly from your computer</li>
                <li>Always send a test email first to review your layout</li>
                <li>Keep subject lines under 60 characters</li>
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* ═══════════════ SUBSCRIBERS TAB ═══════════════ */}
      {tab === "subscribers" && (
        <div className={nl.card}>
          <div className={nl.cardHeader}>
            <h3 className={nl.cardTitle} style={{ margin: 0 }}>
              <FiUsers style={{ verticalAlign: "middle", marginRight: 8 }} />
              All Subscribers ({subscribers.length})
            </h3>
            <button className={nl.refreshBtn} onClick={fetchSubscribers} disabled={subsLoading}>
              <FiRefreshCw className={subsLoading ? nl.spin : ""} />
            </button>
          </div>

          {subsLoading ? (
            <div className={nl.emptyState}>Loading subscribers…</div>
          ) : subscribers.length === 0 ? (
            <div className={nl.emptyState}>No subscribers yet.</div>
          ) : (
            <div className={styles.tableContainer}>
              <table className={styles.adminTable}>
                <thead>
                  <tr>
                    <th>Email</th>
                    <th>Name</th>
                    <th>Company</th>
                    <th>Type</th>
                    <th>Status</th>
                    <th>Date</th>
                  </tr>
                </thead>
                <tbody>
                  {subscribers.map((s) => (
                    <tr key={`${s.type}-${s.id}`}>
                      <td style={{ fontWeight: 600 }}>{s.email}</td>
                      <td>{s.name}</td>
                      <td>{s.company}</td>
                      <td>
                        <span className={`${nl.typeBadge} ${s.type === "member" ? nl.typeMember : nl.typeGuest}`}>
                          {s.type}
                        </span>
                      </td>
                      <td>
                        <span className={`${nl.statusDot} ${s.status === "subscribed" ? nl.statusActive :
                          s.status === "unsubscribed" ? nl.statusInactive : nl.statusDeactivated
                          }`} />
                        {s.status}
                      </td>
                      <td>{new Date(s.date).toLocaleDateString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* ═══════════════ CAMPAIGNS TAB ═══════════════ */}
      {tab === "campaigns" && (
        <div className={nl.card}>
          <div className={nl.cardHeader}>
            <h3 className={nl.cardTitle} style={{ margin: 0 }}>
              <FiClock style={{ verticalAlign: "middle", marginRight: 8 }} />
              Campaign History
            </h3>
            <button className={nl.refreshBtn} onClick={fetchCampaigns} disabled={campaignsLoading}>
              <FiRefreshCw className={campaignsLoading ? nl.spin : ""} />
            </button>
          </div>

          {campaignsLoading ? (
            <div className={nl.emptyState}>Loading campaigns…</div>
          ) : campaigns.length === 0 ? (
            <div className={nl.emptyState}>No campaigns sent yet. Compose and send your first newsletter!</div>
          ) : (
            <div className={nl.campaignList}>
              {campaigns.map((c) => (
                <div key={c.id} className={nl.campaignItem}>
                  <div
                    className={nl.campaignRow}
                    onClick={() => setExpandedCampaign(expandedCampaign === c.id ? null : c.id)}
                  >
                    <div className={nl.campaignInfo}>
                      <strong>{c.subject}</strong>
                      <span className={nl.campaignMeta}>
                        <FiUsers size={12} /> {c.recipient_count} recipients &nbsp;·&nbsp;
                        <FiClock size={12} /> {new Date(c.sent_at).toLocaleString()}
                      </span>
                    </div>
                    <span className={nl.expandIcon}>
                      {expandedCampaign === c.id ? <FiChevronUp /> : <FiChevronDown />}
                    </span>
                  </div>
                  {expandedCampaign === c.id && (
                    <div className={nl.campaignContent}>
                      <div dangerouslySetInnerHTML={{ __html: c.content || "<em>No content recorded.</em>" }} />
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ═══════════════ PREVIEW MODAL ═══════════════ */}
      {showPreview && (
        <div className={nl.modal} onClick={() => setShowPreview(false)}>
          <div className={nl.modalContent} onClick={(e) => e.stopPropagation()}>
            <div className={nl.modalHeader}>
              <h3>Email Preview</h3>
              <button className={nl.modalClose} onClick={() => setShowPreview(false)}><FiX /></button>
            </div>
            <div className={nl.modalBody}>
              <div className={nl.previewMeta}>
                <strong>Subject:</strong> {subject || "(no subject)"}
              </div>
              <div
                className={nl.previewFrame}
                dangerouslySetInnerHTML={{ __html: previewHtml }}
              />
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import styles from "../orders.module.css";

export default function AdminOrderDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const unwrappedParams = use(params);
  const id = unwrappedParams.id;
  const router = useRouter();

  const [order, setOrder] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  // Status state
  const [status, setStatus] = useState("");
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  // Note state
  const [noteContent, setNoteContent] = useState("");
  const [isCustomerNote, setIsCustomerNote] = useState(false);
  const [isAddingNote, setIsAddingNote] = useState(false);

  // Refund state
  const [showRefundModal, setShowRefundModal] = useState(false);
  const [refundAmount, setRefundAmount] = useState("");
  const [refundReason, setRefundReason] = useState("");
  const [isRefunding, setIsRefunding] = useState(false);

  const fetchOrder = async () => {
    try {
      const res = await fetch(`/api/admin/orders/${id}`);
      if (!res.ok) throw new Error("Failed to fetch order");
      const data = await res.json();
      setOrder(data.order);
      setStatus(data.order.status);
    } catch (err) {
      console.error(err);
      alert("Error fetching order detail");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOrder();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id]);

  const handleStatusUpdate = async () => {
    if (status === order.status) return;
    setIsUpdatingStatus(true);
    try {
      const res = await fetch(`/api/admin/orders/${id}/status`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status })
      });
      if (!res.ok) throw new Error("Failed to update status");
      await fetchOrder();
    } catch (err) {
      console.error(err);
      alert("Error updating status");
    } finally {
      setIsUpdatingStatus(false);
    }
  };

  const handleAddNote = async () => {
    if (!noteContent.trim()) return;
    setIsAddingNote(true);
    try {
      const res = await fetch(`/api/admin/orders/${id}/notes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ note: noteContent, is_customer_note: isCustomerNote })
      });
      if (!res.ok) throw new Error("Failed to add note");
      setNoteContent("");
      setIsCustomerNote(false);
      await fetchOrder();
    } catch (err) {
      console.error(err);
      alert("Error adding note");
    } finally {
      setIsAddingNote(false);
    }
  };

  const handleRefund = async () => {
    if (!refundAmount || isNaN(Number(refundAmount)) || Number(refundAmount) <= 0) {
      alert("Please enter a valid amount");
      return;
    }
    setIsRefunding(true);
    try {
      const res = await fetch(`/api/admin/orders/${id}/refunds`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount: refundAmount, reason: refundReason })
      });
      if (!res.ok) throw new Error("Failed to process refund");
      setShowRefundModal(false);
      setRefundAmount("");
      setRefundReason("");
      await fetchOrder();
    } catch (err) {
      console.error(err);
      alert("Error processing refund");
    } finally {
      setIsRefunding(false);
    }
  };

  if (loading) return <div className={styles.container}>Loading order...</div>;
  if (!order) return <div className={styles.container}>Order not found.</div>;

  const totalRefunded = order.refunds?.reduce((sum: number, r: any) => sum + Number(r.amount), 0) || 0;

  return (
    <div className={styles.container}>
      <Link href="/crown-admin/orders" className={styles.actionLink} style={{ display: 'inline-block', marginBottom: '1rem' }}>
        &larr; Back to Orders
      </Link>

      <div className={styles.header}>
        <div>
          <h1>Order #{order.order_number}</h1>
          <p style={{ color: '#64748b', margin: '0.25rem 0 0 0' }}>
            Placed on {new Date(order.created_at).toLocaleString("en-US", { month: "long", day: "numeric", year: "numeric", hour: "numeric", minute: "numeric" })}
          </p>
        </div>

        <div className={styles.statusUpdate}>
          <select 
            className={styles.statusSelect}
            value={status}
            onChange={(e) => setStatus(e.target.value)}
          >
            <option value="pending">Pending</option>
            <option value="processing">Processing</option>
            <option value="on-hold">On Hold</option>
            <option value="completed">Completed</option>
            <option value="cancelled">Cancelled</option>
            <option value="refunded">Refunded</option>
            <option value="failed">Failed</option>
          </select>
          <button 
            className={styles.btn} 
            onClick={handleStatusUpdate}
            disabled={status === order.status || isUpdatingStatus}
          >
            Update
          </button>
        </div>
      </div>

      <div className={styles.detailGrid}>
        {/* Left Column: Order Details */}
        <div>
          <div className={styles.card}>
            <div className={styles.cardHeader}>
              <h2>Addresses</h2>
            </div>
            <div className={styles.addressGrid}>
              <div className={styles.addressBlock}>
                <h3>Billing</h3>
                <p><strong>{order.billing_address?.firstName} {order.billing_address?.lastName}</strong></p>
                {order.billing_address?.companyName && <p>{order.billing_address.companyName}</p>}
                <p>{order.billing_address?.addressLine}</p>
                <p>{order.billing_address?.city}, {order.billing_address?.stateProvince} {order.billing_address?.zipCode}</p>
                <p>{order.billing_address?.country}</p>
                <br/>
                <p>Email: <a href={`mailto:${order.customer_email}`} className={styles.actionLink}>{order.customer_email}</a></p>
                <p>Phone: {order.billing_address?.phone}</p>
              </div>
              <div className={styles.addressBlock}>
                <h3>Shipping</h3>
                <p><strong>{order.shipping_address?.firstName} {order.shipping_address?.lastName}</strong></p>
                {order.shipping_address?.companyName && <p>{order.shipping_address.companyName}</p>}
                <p>{order.shipping_address?.addressLine}</p>
                <p>{order.shipping_address?.city}, {order.shipping_address?.stateProvince} {order.shipping_address?.zipCode}</p>
                <p>{order.shipping_address?.country}</p>
                <br/>
                <p>Method: <strong>{order.shipping_method}</strong></p>
              </div>
            </div>
          </div>

          <div className={styles.card}>
            <div className={styles.cardHeader}>
              <h2>Line Items</h2>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              {order.items?.map((item: any) => (
                <div key={item.id} className={styles.itemRow}>
                  <img src={item.image_url || '/placeholder.png'} alt={item.product_name} className={styles.itemImage} />
                  <div className={styles.itemInfo} style={{ flex: 1 }}>
                    <h4>{item.product_name}</h4>
                    <p>SKU: {item.sku}</p>
                    {item.variation_label && <p>Variation: {item.variation_label}</p>}
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <p style={{ margin: 0 }}>${Number(item.unit_price).toFixed(2)} x {item.quantity}</p>
                    <strong style={{ display: 'block', marginTop: '0.25rem' }}>${Number(item.line_total).toFixed(2)}</strong>
                  </div>
                </div>
              ))}
            </div>

            <hr style={{ border: 'none', borderTop: '1px solid #e2e8f0', margin: '1.5rem 0' }} />

            <table className={styles.totals}>
              <tbody>
                <tr>
                  <th>Items Subtotal:</th>
                  <td>${Number(order.subtotal_amount).toFixed(2)}</td>
                </tr>
                <tr>
                  <th>Shipping:</th>
                  <td>${Number(order.shipping_amount).toFixed(2)}</td>
                </tr>
                <tr>
                  <th>Tax:</th>
                  <td>${Number(order.tax_amount).toFixed(2)}</td>
                </tr>
                <tr>
                  <th className={styles.grandTotal}>Order Total:</th>
                  <td className={styles.grandTotal}>${Number(order.total_amount).toFixed(2)}</td>
                </tr>
                {totalRefunded > 0 && (
                  <tr>
                    <th style={{ color: '#ef4444' }}>Refunded:</th>
                    <td style={{ color: '#ef4444' }}>-${totalRefunded.toFixed(2)}</td>
                  </tr>
                )}
                {totalRefunded > 0 && (
                  <tr>
                    <th className={styles.grandTotal}>Net Total:</th>
                    <td className={styles.grandTotal}>${(Number(order.total_amount) - totalRefunded).toFixed(2)}</td>
                  </tr>
                )}
              </tbody>
            </table>

            <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '1.5rem', gap: '1rem' }}>
              {order.payment_link_url && order.payment_status === 'pending' && (
                <button 
                  className={styles.btnSecondary} 
                  onClick={() => {
                    alert(`Dummy: Payment link sent to ${order.customer_email}\nLink: ${order.payment_link_url}`);
                  }}
                >
                  Send Payment Link
                </button>
              )}
              <button className={styles.btnDanger} onClick={() => setShowRefundModal(true)}>
                Refund
              </button>
            </div>
          </div>
        </div>

        {/* Right Column: Timeline & Notes */}
        <div>
          <div className={styles.card}>
            <div className={styles.cardHeader}>
              <h2>Order Timeline & Notes</h2>
            </div>

            <div className={styles.timeline}>
              {order.activity_logs?.map((log: any) => {
                let logClass = styles.system;
                if (log.is_customer_note) logClass = styles.customer;
                else if (log.admin_id) logClass = styles.admin;

                return (
                  <div key={log.id} className={`${styles.timelineItem} ${logClass}`}>
                    <div className={styles.timelineHeader}>
                      <span className={styles.timelineAuthor}>
                        {log.admin_name || 'System'} {log.is_customer_note ? '(Note to customer)' : ''}
                      </span>
                      <span>{new Date(log.created_at).toLocaleString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "numeric" })}</span>
                    </div>
                    <p className={styles.timelineNote}>{log.note}</p>
                  </div>
                );
              })}
              {order.activity_logs?.length === 0 && (
                <p style={{ color: '#64748b', fontSize: '0.9rem' }}>No activity logs yet.</p>
              )}
            </div>

            <div className={styles.addNote}>
              <h3 style={{ fontSize: '0.95rem', margin: '0 0 0.5rem 0' }}>Add Note</h3>
              <textarea 
                placeholder="Type a note..." 
                value={noteContent}
                onChange={(e) => setNoteContent(e.target.value)}
              />
              <div className={styles.noteActions}>
                <label style={{ fontSize: '0.85rem', display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1 }}>
                  <input 
                    type="checkbox" 
                    checked={isCustomerNote} 
                    onChange={(e) => setIsCustomerNote(e.target.checked)}
                  />
                  Note to customer
                </label>
                <button 
                  className={styles.btnOutline} 
                  onClick={handleAddNote}
                  disabled={isAddingNote || !noteContent.trim()}
                >
                  Add Note
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Refund Modal */}
      {showRefundModal && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, 
          background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000
        }}>
          <div style={{
            background: 'white', padding: '2rem', borderRadius: '8px', width: '100%', maxWidth: '400px'
          }}>
            <h2 style={{ marginTop: 0 }}>Issue Refund</h2>
            <p style={{ fontSize: '0.9rem', color: '#64748b', marginBottom: '1rem' }}>
              Note: This only records the refund in the database. You must still issue the refund via your payment provider (e.g., Stripe/PayPal).
            </p>
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', fontSize: '0.9rem', marginBottom: '0.25rem' }}>Amount ($)</label>
              <input 
                type="number" 
                step="0.01" 
                max={Number(order.total_amount) - totalRefunded}
                value={refundAmount}
                onChange={(e) => setRefundAmount(e.target.value)}
                style={{ width: '100%', padding: '0.5rem', border: '1px solid #cbd5e1', borderRadius: '4px' }}
              />
              <small style={{ color: '#64748b' }}>
                Max available: ${(Number(order.total_amount) - totalRefunded).toFixed(2)}
              </small>
            </div>
            <div style={{ marginBottom: '1.5rem' }}>
              <label style={{ display: 'block', fontSize: '0.9rem', marginBottom: '0.25rem' }}>Reason (Optional)</label>
              <input 
                type="text" 
                value={refundReason}
                onChange={(e) => setRefundReason(e.target.value)}
                style={{ width: '100%', padding: '0.5rem', border: '1px solid #cbd5e1', borderRadius: '4px' }}
              />
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem' }}>
              <button className={styles.btnOutline} onClick={() => setShowRefundModal(false)}>Cancel</button>
              <button className={styles.btnDanger} onClick={handleRefund} disabled={isRefunding}>Process Refund</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import styles from "./admin.module.css";

interface DashboardData {
  stats: {
    totalBlogs: number;
    publishedBlogs: number;
    draftBlogs: number;
  };
  recentBlogs: any[];
}

export default function AdminDashboard() {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await fetch(`/api/admin/dashboard`, {
          credentials: "include"
        });
        if (!res.ok) throw new Error("Failed to fetch dashboard");
        const json = await res.json();
        setData(json);
      } catch (err) {
        setError("Could not load dashboard data.");
      } finally {
        setLoading(false);
      }
    };

    fetchDashboard();
  }, []);

  if (loading) return <div>Loading dashboard...</div>;
  if (error) return <div className={styles.errorMessage}>{error}</div>;

  return (
    <>
      <div className={styles.pageHeader}>
        <h1 className={styles.pageTitle}>Dashboard Overview</h1>
        <Link href="/crown-admin/blogs/new" className={styles.btnPrimary}>
          Create New Blog
        </Link>
      </div>

      <div className={styles.statsGrid}>
        <div className={styles.statCard}>
          <div className={styles.statCardTitle}>Total Blogs</div>
          <div className={styles.statCardValue}>{data?.stats.totalBlogs || 0}</div>
        </div>
        <div className={styles.statCard}>
          <div className={styles.statCardTitle}>Published</div>
          <div className={styles.statCardValue}>{data?.stats.publishedBlogs || 0}</div>
        </div>
        <div className={styles.statCard}>
          <div className={styles.statCardTitle}>Drafts</div>
          <div className={styles.statCardValue}>{data?.stats.draftBlogs || 0}</div>
        </div>
      </div>

      <div style={{ marginTop: '3rem' }}>
        <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem', color: '#1a1a2e' }}>Recent Blogs</h2>
        <div className={styles.tableContainer}>
          <table className={styles.adminTable}>
            <thead>
              <tr>
                <th>Title</th>
                <th>Status</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {data?.recentBlogs.length === 0 ? (
                <tr>
                  <td colSpan={4} style={{ textAlign: 'center', padding: '2rem' }}>
                    No blogs found. Create one to get started!
                  </td>
                </tr>
              ) : (
