"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import styles from "./users.module.css";
import { format } from "date-fns";

type Role = { name: string };
type User = {
  id: string;
  username: string;
  email: string;
  full_name: string;
  mobile: string;
  is_active: boolean;
  created_at: string;
  roles: Role | null;
};

export default function AdminUsersPage() {
  const [users, setUsers] = useState<User[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);

  // Filters
  const [search, setSearch] = useState("");
  const [roleId, setRoleId] = useState("");
  const [isActive, setIsActive] = useState("");
  const [page, setPage] = useState(1);
  const limit = 20;

  // Options
  const [rolesList, setRolesList] = useState<{id: string, name: string}[]>([]);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const q = new URLSearchParams({
        page: page.toString(),
        limit: limit.toString(),
        ...(search && { search }),
        ...(roleId && { role_id: roleId }),
        ...(isActive && { is_active: isActive }),
      });
      const res = await fetch(`/api/admin/users?${q.toString()}`);
      if (res.ok) {
        const data = await res.json();
        setUsers(data.users || []);
        setTotal(data.total || 0);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchRoles = async () => {
    try {
      const res = await fetch('/api/admin/roles');
      if (res.ok) {
        setRolesList(await res.json());
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchRoles();
  }, []);

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      fetchUsers();
    }, 300);
    return () => clearTimeout(delayDebounce);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [search, roleId, isActive, page]);

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h1>Users</h1>
        <Link href="/crown-admin/users/new" className={styles.createBtn}>
          + New User
        </Link>
      </div>

      <div className={styles.filters}>
        <input 
          type="text" 
          placeholder="Search by name, email, username..." 
          className={styles.searchBar}
          value={search}
          onChange={e => { setSearch(e.target.value); setPage(1); }}
        />
        <select 
          className={styles.filterSelect}
          value={roleId}
          onChange={e => { setRoleId(e.target.value); setPage(1); }}
        >
          <option value="">All Roles</option>
          {rolesList.map(r => (
            <option key={r.id} value={r.id}>{r.name}</option>
          ))}
        </select>
        <select 
          className={styles.filterSelect}
          value={isActive}
          onChange={e => { setIsActive(e.target.value); setPage(1); }}
        >
          <option value="">All Statuses</option>
          <option value="true">Active</option>
          <option value="false">Inactive</option>
        </select>
      </div>

      <div className={styles.tableWrapper}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Username</th>
              <th>Full Name</th>
              <th>Email</th>
              <th>Role</th>
              <th>Status</th>
              <th>Created</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={7} style={{textAlign:'center', padding:'2rem'}}>Loading...</td></tr>
            ) : users.length === 0 ? (
              <tr><td colSpan={7} style={{textAlign:'center', padding:'2rem'}}>No users found.</td></tr>
            ) : (
              users.map(u => (
                <tr key={u.id}>
                  <td>{u.username}</td>
                  <td>{u.full_name}</td>
                  <td>{u.email}</td>
                  <td>
                    <span className={styles.roleBadge}>{u.roles?.name || 'None'}</span>
                  </td>
                  <td>
                    <span className={`${styles.statusBadge} ${u.is_active ? styles.statusActive : styles.statusInactive}`}>
                      {u.is_active ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>{format(new Date(u.created_at), "MMM d, yyyy")}</td>
                  <td>
                    <Link href={`/crown-admin/users/${u.id}`} className={styles.actionLink}>Edit</Link>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <div className={styles.pagination}>
        <button 
          className={styles.pageBtn} 
          disabled={page === 1} 
          onClick={() => setPage(p => p - 1)}
        >
          Previous
        </button>
        <span className={styles.pageInfo}>Page {page} of {Math.ceil(total / limit) || 1}</span>
        <button 
          className={styles.pageBtn} 
          disabled={page * limit >= total} 
          onClick={() => setPage(p => p + 1)}
        >
          Next
        </button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { FiX } from "react-icons/fi";
import styles from "./HeroBanner.module.css";

interface Banner {
  id: string;
  heading1: string;
  heading2: string;
  paragraph: string;
  cta_text: string;
  cta_link: string;
  bg_image_desktop: string;
  bg_image_mobile: string;
  overlay_color: string;
  overlay_opacity: number;
  text_color: string;
  text_align: string;
  banner_height: string;
  padding_x: number;
  padding_y: number;
}

const heightMap: Record<string, string> = {
  small: "300px",
  medium: "450px",
  large: "600px",
  fullscreen: "100vh",
};

export default function HeroBanner() {
  const [banner, setBanner] = useState<Banner | null>(null);
  const [loaded, setLoaded] = useState(false);
  const [isHidden, setIsHidden] = useState(false);

  useEffect(() => {
    const fetchBanner = async () => {
      // Client-side fallback check
      const views = parseInt(sessionStorage.getItem('bannerViews') || '0', 10);
      if (views >= 2) {
        setLoaded(true);
        return;
      }

      try {
        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_URL}/api/banners/active`,
          { credentials: 'include' }
        );
        if (!res.ok) return;
        const data = await res.json();
        if (data.banner) {
          setBanner(data.banner);
          sessionStorage.setItem('bannerViews', (views + 1).toString());
        }
      } catch {
        // Silently fail — homepage still works without a banner
      } finally {
        setLoaded(true);
      }
    };

    fetchBanner();
  }, []);

  // Don't render anything if no active banner or if user closed it
  if (!loaded || !banner || isHidden) return null;

  const bannerHeight = heightMap[banner.banner_height] || "600px";

  // Decide which image to show
  // On the server render / initial load we don't know viewport,
  // so we use CSS to toggle. But since this is a client component,
  // we can check window width too.
  const isMobile = typeof window !== "undefined" && window.innerWidth <= 768;
  const bgImage =
    isMobile && banner.bg_image_mobile
      ? banner.bg_image_mobile
      : banner.bg_image_desktop;

  const isExternal =
    banner.cta_link &&
    (banner.cta_link.startsWith("http://") ||
      banner.cta_link.startsWith("https://"));

  return (
    <section className={`${styles.bannerWrapper} ${styles.bannerFadeIn}`}>
      <button 
        className={styles.closeBannerBtn} 
        onClick={() => setIsHidden(true)}
        aria-label="Close Banner"
      >
        <FiX size={20} />
      </button>
      <div
        className={styles.bannerInner}
        style={{
          backgroundImage: bgImage ? `url(${bgImage})` : "none",
          minHeight: bannerHeight,
          justifyContent:
            banner.text_align === "left"
              ? "flex-start"
              : banner.text_align === "right"
                ? "flex-end"
                : "center",
        }}
      >
        {/* Overlay */}
        <div
          className={styles.overlay}
          style={{
            backgroundColor: banner.overlay_color,
            opacity: banner.overlay_opacity / 100,
          }}
        />

        {/* Content */}
        <div
          className={styles.content}
          style={{
            color: banner.text_color,
            textAlign: banner.text_align as any,
            padding: `${banner.padding_y}px ${banner.padding_x}px`,
          }}
        >
          {banner.heading1 && (
            <h2 className={styles.heading1}>{banner.heading1}</h2>
          )}
          {banner.heading2 && (
            <h3 className={styles.heading2}>{banner.heading2}</h3>
          )}
          {banner.paragraph && (
            <p
              className={styles.paragraph}
              style={{
                margin:
                  banner.text_align === "center"
                    ? "0 auto 2rem auto"
                    : banner.text_align === "right"
                      ? "0 0 2rem auto"
                      : "0 0 2rem 0",
              }}
            >
              {banner.paragraph}
            </p>
          )}
          {banner.cta_text && banner.cta_link && (
            isExternal ? (
              <a
                href={banner.cta_link}
                className={styles.ctaButton}
                style={{
                  color: banner.text_color,
                  borderColor: banner.text_color,
                }}
                target="_blank"
                rel="noopener noreferrer"
              >
                {banner.cta_text}
              </a>
            ) : (
              <Link
                href={banner.cta_link}
                className={styles.ctaButton}
                style={{
                  color: banner.text_color,
                  borderColor: banner.text_color,
                }}
              >
                {banner.cta_text}
              </Link>
            )
          )}
        </div>
      </div>
    </section>
  );
}

