    ]
  },
  'mountings': {
    title: 'MOUNTINGS',
    slug: 'mountings',
    links: [
      { label: 'Ring Mountings', href: '/products?category=ring-mountings' },
      { label: 'Pendant Mountings', href: '/products?category=pendant-mountings' },
      { label: 'Earring Mountings', href: '/products?category=earring-mountings' },
